import React, { useEffect, useState } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByKey, limitToLast, get, endAt } from 'firebase/database';
import { OrderRecord, STATUS_OPTIONS } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 100;

interface ReconciliationProps {
  onEdit: (orderId: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [noMoreData, setNoMoreData] = useState(false);

  // Pagination cursor (using keys for reliable pagination)
  const [oldestLoadedKey, setOldestLoadedKey] = useState<string | null>(null);

  // Helper to safely parse date for sorting
  const getOrderDate = (order: OrderRecord) => {
    const dateVal = order.OrderDate || order['Order Date'] || order.Date;
    if (!dateVal) return 0;
    return new Date(dateVal).getTime();
  };

  // --- Data Fetching ---

  const fetchLatestOrders = async () => {
    setLoading(true);
    setError(null);
    try {
      const ordersRef = ref(db, 'order_management/master_recon_file');
      // CHANGED: Use orderByKey() (implicit or explicit) instead of orderByChild('OrderDate')
      // This ensures we get data even if 'OrderDate' is missing or named differently.
      const q = query(ordersRef, orderByKey(), limitToLast(PAGE_SIZE));

      const snapshot = await get(q);
      if (snapshot.exists()) {
        const data = snapshot.val();
        const loadedOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // Client-side sort by date descending
        loadedOrders.sort((a, b) => getOrderDate(b) - getOrderDate(a));

        setOrders(loadedOrders);

        // For pagination, we track the 'oldest' key (which is actually the first in the raw result from limitToLast)
        // Since limitToLast returns keys in ascending order, the first key in Object.keys(data) is roughly the oldest
        // But Object.keys order isn't guaranteed sorted in JS engines for all types, so let's sort keys to find cursor.
        const sortedKeys = Object.keys(data).sort();
        if (sortedKeys.length > 0) {
           setOldestLoadedKey(sortedKeys[0]); 
        }
      } else {
        setOrders([]);
      }
    } catch (error: any) {
      console.error("Error fetching orders:", error);
      setError(error.message || "Failed to load data");
    } finally {
      setLoading(false);
    }
  };

  const loadMore = async () => {
    if (!oldestLoadedKey) return;
    setLoading(true);

    try {
      const ordersRef = ref(db, 'order_management/master_recon_file');
      // Pagination using key
      const q = query(
        ordersRef, 
        orderByKey(),
        endAt(oldestLoadedKey), 
        limitToLast(PAGE_SIZE + 1)
      );

      const snapshot = await get(q);
      if (snapshot.exists()) {
        const data = snapshot.val();
        const newOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // Filter out the exact cursor key to avoid duplicates
        const filteredNewOrders = newOrders.filter(o => o.Code !== oldestLoadedKey);

        if (filteredNewOrders.length === 0) {
          setNoMoreData(true);
        } else {
            // Sort new batch
            filteredNewOrders.sort((a, b) => getOrderDate(b) - getOrderDate(a));

            setOrders(prev => {
              // Merge and re-sort full list to be safe
              const combined = [...prev, ...filteredNewOrders];
              return combined.sort((a, b) => getOrderDate(b) - getOrderDate(a));
            });

            const sortedKeys = Object.keys(data).sort();
            if (sortedKeys.length > 0) {
               setOldestLoadedKey(sortedKeys[0]); 
            }
        }
      } else {
        setNoMoreData(true);
      }
    } catch (error: any) {
      console.error("Error loading more:", error);
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLatestOrders();
  }, []);

  // --- Filtering ---

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchTerm(e.target.value.toLowerCase());
  };

  const toggleStatusFilter = (status: string) => {
    setStatusFilters(prev => 
      prev.includes(status) 
        ? prev.filter(s => s !== status) 
        : [...prev, status]
    );
  };

  const filteredOrders = orders.filter(order => {
    const matchesSearch = 
      (String(order.OrderNumber) || '').toLowerCase().includes(searchTerm) ||
      (String(order.SalesDocument) || '').toLowerCase().includes(searchTerm) ||
      (String(order.BatchNumber) || '').toLowerCase().includes(searchTerm) ||
      (String(order["Material Number"]) || '').toLowerCase().includes(searchTerm) ||
      (String(order.ClubName) || '').toLowerCase().includes(searchTerm);

    let matchesStatus = true;
    if (statusFilters.length > 0) {
      matchesStatus = statusFilters.some(filter => {
        const s = (order.Status || '').toLowerCase();
        if (filter === 'Shipped') return s.includes('shipped');
        if (filter === 'Canceled') return s.includes('canceled');
        if (filter === 'Not shipped') return !s.includes('shipped');
        if (filter === 'Duplicate') return s.includes('duplicate');
        if (filter === 'PA') return s.includes('pa');
        return s.includes(filter.toLowerCase());
      });
    }

    return matchesSearch && matchesStatus;
  });

  const tableHeaders = [
    'Order #', 'Sales Doc', 'Order Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'UPS Tracking'
  ];

  if (isAdmin) {
    tableHeaders.push('Action');
  }

  return (
    <div className="flex flex-col gap-6">

      {/* Header & Controls Card */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-5 flex flex-col md:flex-row gap-4 justify-between items-center z-20">

        {/* Search */}
        <div className="relative w-full md:w-96 group">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none transition-colors group-focus-within:text-brand-500">
            <svg className="h-5 w-5 text-slate-400 group-focus-within:text-brand-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-3 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm leading-5 placeholder-slate-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all shadow-inner"
            placeholder="Search orders, materials, clubs..."
            value={searchTerm}
            onChange={handleSearchChange}
          />
        </div>

        {/* Filter */}
        <div className="relative w-full md:w-auto">
          <button
            onClick={() => setIsFilterOpen(!isFilterOpen)}
            className={`w-full md:w-auto inline-flex justify-center items-center px-5 py-2.5 border rounded-lg text-sm font-medium transition-all ${isFilterOpen || statusFilters.length > 0 ? 'bg-brand-50 text-brand-700 border-brand-200 shadow-sm' : 'border-slate-200 text-slate-600 bg-white hover:bg-slate-50 hover:border-slate-300'}`}
          >
            <svg className={`mr-2 h-4 w-4 ${statusFilters.length > 0 ? 'text-brand-500' : 'text-slate-400'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
            </svg>
            Filter Status 
            {statusFilters.length > 0 && (
              <span className="ml-2 bg-brand-200 text-brand-800 text-xs py-0.5 px-2 rounded-full font-bold">
                {statusFilters.length}
              </span>
            )}
          </button>

          {isFilterOpen && (
            <>
              <div className="fixed inset-0 z-10 cursor-default" onClick={() => setIsFilterOpen(false)}></div>
              <div className="absolute right-0 mt-2 w-64 rounded-xl shadow-card bg-white ring-1 ring-black ring-opacity-5 z-20 overflow-hidden animate-fade-in-up">
                <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Filter by Status</span>
                    <button onClick={() => { setStatusFilters([]); setIsFilterOpen(false); }} className="text-xs text-brand-600 hover:underline">Clear all</button>
                </div>
                <div className="py-2" role="menu">
                  {STATUS_OPTIONS.map(option => (
                    <label key={option} className="flex items-center px-4 py-3 hover:bg-slate-50 cursor-pointer transition-colors">
                      <input
                        type="checkbox"
                        checked={statusFilters.includes(option)}
                        onChange={() => toggleStatusFilter(option)}
                        className="h-4 w-4 text-brand-600 focus:ring-brand-500 border-slate-300 rounded transition duration-150 ease-in-out"
                      />
                      <span className="ml-3 text-sm text-slate-700 font-medium">{option}</span>
                    </label>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Main Table Card */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col h-[calc(100vh-280px)]">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full divide-y divide-slate-100">
            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {tableHeaders.map(head => (
                  <th key={head} className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap bg-slate-50">
                    {head}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={tableHeaders.length} className="px-6 py-10 text-center">
                      <div className="inline-flex items-center px-4 py-2 rounded-lg bg-red-50 text-red-700 border border-red-100">
                         <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                         {error}
                      </div>
                    </td>
                 </tr>
              ) : loading && orders.length === 0 ? (
                 <tr><td colSpan={tableHeaders.length} className="text-center py-20 text-slate-400">Loading order data...</td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr><td colSpan={tableHeaders.length} className="text-center py-20 text-slate-400">No orders found matching your criteria.</td></tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = order.Status?.toLowerCase() || '';
                  let statusColor = 'bg-slate-100 text-slate-600';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-100 text-emerald-700 ring-1 ring-emerald-600/20';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-100 text-rose-700 ring-1 ring-rose-600/20';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-100 text-orange-700 ring-1 ring-orange-600/20';
                  else if (status.includes('pa')) statusColor = 'bg-violet-100 text-violet-700 ring-1 ring-violet-600/20';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-slate-800 group-hover:text-brand-600">{order.OrderNumber}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.SalesDocument}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.OrderDate}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.BatchNumber}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.Year}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600" title={order["Material Number"]}>
                        <div className="max-w-[150px] truncate">{order["Material Number"]}</div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.ClubName}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{order.OrderType}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className={`px-2.5 py-0.5 inline-flex text-xs leading-5 font-bold rounded-full ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{order.CDD}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 font-mono text-xs">{order.UPSTrackingNumber}</td>

                      {isAdmin && (
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>

          {!noMoreData && !loading && !error && filteredOrders.length > 0 && (
            <div className="p-4 flex justify-center bg-white border-t border-slate-100">
              <button 
                onClick={loadMore}
                className="text-sm font-medium text-brand-600 hover:text-brand-800 bg-brand-50 hover:bg-brand-100 px-6 py-2 rounded-full transition-colors"
              >
                Load older records
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByKey, orderByChild, limitToLast, get, endAt, startAt, equalTo } from 'firebase/database';
import { OrderRecord, STATUS_OPTIONS } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

interface ReconciliationProps {
  onEdit: (orderId: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // Data States
  const [orders, setOrders] = useState<OrderRecord[]>([]); // For Browse Mode
  const [searchResults, setSearchResults] = useState<OrderRecord[]>([]); // For Search Mode

  // UI States
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearchTerm, setDebouncedSearchTerm] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Pagination States
  const [oldestLoadedKey, setOldestLoadedKey] = useState<string | null>(null);
  const [noMoreData, setNoMoreData] = useState(false);

  // Debounce Logic for Search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearchTerm(searchTerm);
    }, 600); // Wait 600ms after user stops typing
    return () => clearTimeout(timer);
  }, [searchTerm]);

  // Determine Active Mode
  const isSearchMode = debouncedSearchTerm.length > 0;

  // --- Helper: Date Sorting ---
  const getOrderDate = (order: OrderRecord) => {
    const dateVal = order.OrderDate || order['Order Date'] || order.Date;
    if (!dateVal) return 0;
    return new Date(dateVal).getTime();
  };

  // --- Mode 1: Browse (Pagination) ---
  const fetchLatestOrders = async () => {
    setLoading(true);
    setError(null);
    try {
      const ordersRef = ref(db, 'order_management/master_recon_file');
      // Fetch latest N records
      const q = query(ordersRef, orderByKey(), limitToLast(PAGE_SIZE));

      const snapshot = await get(q);
      if (snapshot.exists()) {
        const data = snapshot.val();
        const loadedOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // Client-side sort descending by date for display
        loadedOrders.sort((a, b) => getOrderDate(b) - getOrderDate(a));
        setOrders(loadedOrders);

        // Update cursor
        const sortedKeys = Object.keys(data).sort();
        if (sortedKeys.length > 0) {
           setOldestLoadedKey(sortedKeys[0]); 
        }
      } else {
        setOrders([]);
      }
    } catch (error: any) {
      console.error("Error fetching orders:", error);
      setError(error.message || "Failed to load data");
    } finally {
      setLoading(false);
    }
  };

  const loadMore = async () => {
    if (!oldestLoadedKey || isSearchMode) return;
    setLoading(true);

    try {
      const ordersRef = ref(db, 'order_management/master_recon_file');
      const q = query(
        ordersRef, 
        orderByKey(),
        endAt(oldestLoadedKey), 
        limitToLast(PAGE_SIZE + 1)
      );

      const snapshot = await get(q);
      if (snapshot.exists()) {
        const data = snapshot.val();
        const newOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        const filteredNewOrders = newOrders.filter(o => o.Code !== oldestLoadedKey);

        if (filteredNewOrders.length === 0) {
          setNoMoreData(true);
        } else {
            filteredNewOrders.sort((a, b) => getOrderDate(b) - getOrderDate(a));
            setOrders(prev => {
              const combined = [...prev, ...filteredNewOrders];
              return combined.sort((a, b) => getOrderDate(b) - getOrderDate(a));
            });
            const sortedKeys = Object.keys(data).sort();
            if (sortedKeys.length > 0) {
               setOldestLoadedKey(sortedKeys[0]); 
            }
        }
      } else {
        setNoMoreData(true);
      }
    } catch (error: any) {
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };

  // --- Mode 2: Search (Server-Side) ---
  const executeSearch = async (term: string) => {
    setLoading(true);
    setError(null);
    setSearchResults([]);

    try {
      const ordersRef = ref(db, 'order_management/master_recon_file');

      // Strategy: Search by OrderNumber (indexed).
      // We use startAt/endAt to allow for string matches or exact number matches
      // This requires ".indexOn": ["OrderNumber"] in Security Rules

      // Note: This logic assumes user searches for OrderNumber. 
      // Searching all fields on server-side is not possible in RTDB without external services like Algolia.
      const q = query(
        ordersRef, 
        orderByChild('OrderNumber'), 
        startAt(term), 
        endAt(term + "\uf8ff"),
        limitToLast(50) // Cap results for performance
      );

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const data = snapshot.val();
        const results: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));
        // Sort search results by date
        results.sort((a, b) => getOrderDate(b) - getOrderDate(a));
        setSearchResults(results);
      } else {
        // Fallback: If no OrderNumber found, we can't easily search other fields server-side efficiently.
        // We set empty to show "No results".
        setSearchResults([]);
      }

    } catch (err: any) {
      console.error("Search error:", err);
      // Friendly error if index is missing
      if (err.message.includes('index')) {
        setError("Missing Database Index. Please ask admin to index 'OrderNumber'.");
      } else {
        setError("Search failed. Ensure you are searching by exact Order Number.");
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Effects ---

  // Initial Load
  useEffect(() => {
    fetchLatestOrders();
  }, []);

  // Trigger Search when debounced term changes
  useEffect(() => {
    if (debouncedSearchTerm) {
      executeSearch(debouncedSearchTerm);
    } else {
      setSearchResults([]); // Clear search
    }
  }, [debouncedSearchTerm]);

  // --- Filtering (Client-side for Status only) ---
  const toggleStatusFilter = (status: string) => {
    setStatusFilters(prev => 
      prev.includes(status) ? prev.filter(s => s !== status) : [...prev, status]
    );
  };

  // Select data source based on mode
  const activeData = isSearchMode ? searchResults : orders;

  // Apply Status filters to whichever data is active
  const displayedOrders = activeData.filter(order => {
    if (statusFilters.length === 0) return true;
    const s = (order.Status || '').toLowerCase();
    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Not shipped') return !s.includes('shipped');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      return s.includes(filter.toLowerCase());
    });
  });

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Header & Controls */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-5 flex flex-col md:flex-row gap-4 justify-between items-center z-20">

        {/* Search Input */}
        <div className="relative w-full md:w-96 group">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none transition-colors group-focus-within:text-brand-500">
            <svg className="h-5 w-5 text-slate-400 group-focus-within:text-brand-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-3 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm leading-5 placeholder-slate-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all shadow-inner"
            placeholder="Search by Order Number..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {isSearchMode && (
            <div className="absolute inset-y-0 right-0 pr-3 flex items-center">
              {loading ? (
                <svg className="animate-spin h-4 w-4 text-brand-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
              ) : (
                <button onClick={() => setSearchTerm('')} className="text-slate-400 hover:text-slate-600">
                  <svg className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                </button>
              )}
            </div>
          )}
        </div>

        {/* Filter Dropdown */}
        <div className="relative w-full md:w-auto">
          <button
            onClick={() => setIsFilterOpen(!isFilterOpen)}
            className={`w-full md:w-auto inline-flex justify-center items-center px-5 py-2.5 border rounded-lg text-sm font-medium transition-all ${isFilterOpen || statusFilters.length > 0 ? 'bg-brand-50 text-brand-700 border-brand-200 shadow-sm' : 'border-slate-200 text-slate-600 bg-white hover:bg-slate-50 hover:border-slate-300'}`}
          >
            <svg className={`mr-2 h-4 w-4 ${statusFilters.length > 0 ? 'text-brand-500' : 'text-slate-400'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
            </svg>
            Filter Status 
            {statusFilters.length > 0 && (
              <span className="ml-2 bg-brand-200 text-brand-800 text-xs py-0.5 px-2 rounded-full font-bold">
                {statusFilters.length}
              </span>
            )}
          </button>

          {isFilterOpen && (
            <>
              <div className="fixed inset-0 z-10 cursor-default" onClick={() => setIsFilterOpen(false)}></div>
              <div className="absolute right-0 mt-2 w-64 rounded-xl shadow-card bg-white ring-1 ring-black ring-opacity-5 z-20 overflow-hidden animate-fade-in-up">
                <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Filter by Status</span>
                    <button onClick={() => { setStatusFilters([]); setIsFilterOpen(false); }} className="text-xs text-brand-600 hover:underline">Clear all</button>
                </div>
                <div className="py-2" role="menu">
                  {STATUS_OPTIONS.map(option => (
                    <label key={option} className="flex items-center px-4 py-3 hover:bg-slate-50 cursor-pointer transition-colors">
                      <input
                        type="checkbox"
                        checked={statusFilters.includes(option)}
                        onChange={() => toggleStatusFilter(option)}
                        className="h-4 w-4 text-brand-600 focus:ring-brand-500 border-slate-300 rounded transition duration-150 ease-in-out"
                      />
                      <span className="ml-3 text-sm text-slate-700 font-medium">{option}</span>
                    </label>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* 2. Table Container */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
