              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - WIDE */}
              <col className="w-40" /> {/* Club */}
              <col className="w-20" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Order #</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Sales Doc</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Date</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Batch</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Year</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Material</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Club</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Type</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Status</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">CDD</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate">Tracking</th>
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Action</th>}
