                 </tr>
              ) : loading && displayedOrders.length === 0 ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">Loading data...</td></tr>
              ) : displayedOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {isSearchMode 
                        ? `No orders found matching "${debouncedSearchTerm}". Try checking the Order #.` 
