    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, Query, limitToFirst, startAt } from 'firebase/database';
import { OrderRecord, STATUS_OPTIONS } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber', type: 'exact' },
  { label: 'Material', key: 'Material Number', type: 'exact' }, // Use 'exact' for strict matching or 'string' for partial if needed, but RTDB partial is limited
  { label: 'Sales Document', key: 'SalesDocument', type: 'exact' }
];

interface Cursor {
  value: string | number;
  key: string;
}

export const Reconciliation: React.FC = ({ onEdit }: any) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  // We store the 'endAt' cursor for every page we visit. 
  // Index 1 stores the cursor needed to fetch Page 1 (which is null/undefined).
  // Index 2 stores the cursor needed to fetch Page 2 (which is the last item of Page 1).
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (page: number, currentCursor: Cursor | null, searchParams: {field: string, text: string} | null) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q: Query;

      if (searchParams) {
        // --- SEARCH MODE ---
        // Searches typically look for specific matches.
        // We use limitToFirst because usually search results are best viewed A-Z or strict match.
        // However, if we want consistency with the "Newest" logic, strict sorting by Date AND filtering by OrderNumber 
        // is impossible in RTDB without a composite key.
        // We will prioritize the Filter Index.

        // Note: For 'Material Number', if you want to support prefix search (starts with), use startAt().
        // For this implementation, we stick to strict equality for accuracy on ID fields.

        let baseQuery = query(dbRef, orderByChild(searchParams.field));

        if (currentCursor) {
            // Pagination for Search Results
            // We use equalTo for the filter, but RTDB pagination with equalTo is tricky.
            // We usually rely on startAt/endAt acting as the cursor for the sorted field.
            // Since we are filtering by X, the sort order is X.
            // This basic implementation supports simple pagination for exact matches (if there are > 50 matches).
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
            // Page 1 Search
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- BROWSE MODE (Default) ---
        // Sort by OrderDate (Newest First)
        // Strategy: limitToLast returns oldest->newest. We fetch, then reverse client-side.
        // To paginate backwards (into history), we use endAt(last_seen_date, last_seen_key).

        if (currentCursor) {
           // Fetching Page 2+
           // We ask for PAGE_SIZE + 1 so we can overlap the cursor and drop it to ensure continuity
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
           // Fetching Page 1
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE));
        }
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const data = snapshot.val();
        let loadedOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // --- Post-Processing ---

        // 1. Sort: Firebase returns data sorted by the index key ascending.
        // For Dates: Oldest -> Newest. We want Newest -> Oldest.
        // For Search: A -> Z.

        if (!searchParams) {
          // Sort by Date Descending
          loadedOrders.sort((a, b) => {
             const dateA = new Date(a.OrderDate || 0).getTime();
             const dateB = new Date(b.OrderDate || 0).getTime();
             return dateB - dateA;
          });
        } else {
          // For search, usually we just keep Firebase order or sort by date locally if small result set
          loadedOrders.sort((a, b) => {
             const dateA = new Date(a.OrderDate || 0).getTime();
             const dateB = new Date(b.OrderDate || 0).getTime();
             return dateB - dateA;
          });
        }

        // 2. Handle Pagination Overlap
        // If we used a cursor (Page 2+), the query includes the cursor record itself. We must remove it.
        if (currentCursor) {
           // The cursor record will be at the very top (because we sorted desc) or match exact key
           loadedOrders = loadedOrders.filter(o => o.Code !== currentCursor.key);
        }

        // 3. Check for "Next Page" availability
        // If we got fewer records than requested, we are at the end.
        if (loadedOrders.length < PAGE_SIZE && currentCursor) {
            setHasNextPage(false);
        } else if (loadedOrders.length === 0) {
            setHasNextPage(false);
        } else {
            setHasNextPage(true);
        }

        setOrders(loadedOrders);

        // 4. Prepare Cursor for *Next* Page
        // The last item in our current view is the "endAt" point for the *next* page fetch.
        if (loadedOrders.length > 0) {
           const lastItem = loadedOrders[loadedOrders.length - 1];
           const nextCursorValue = searchParams ? lastItem[searchParams.field] : lastItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: lastItem.Code });
             return newMap;
           });
        }

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      if (err.message.includes('index')) {
        setError(`Missing Index: Please add ".indexOn": ["OrderDate", "${searchField}"] to Firebase Rules.`);
      } else {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    // Reset pagination and enter search mode
    setCurrentPage(1);
    setCursorStack(new Map()); // Clear history
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    // We can only go to a page if we have its cursor (or it's page 1)
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  // --- Effects ---

  // Trigger fetch when Page or Mode changes
  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    fetchOrders(currentPage, cursor, activeSearch);
  }, [currentPage, activeSearch]); // We don't depend on cursorStack changes, only page/search changes


  // --- Render Helpers ---

  // Generate pagination buttons (1, 2, 3...)
  const renderPaginationNumbers = () => {
    const pages = [];
    // We show pages we have "discovered" (keys exist in stack) plus the current page
    // This creates a "1 2 3 4 ..." effect as user browses
    const maxKnownPage = Math.max(...Array.from(cursorStack.keys()), 1);

    // Logic to show a window of pages (e.g., current - 2 to current + 2)
    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    // If we haven't visited page 5, we can't strictly let them click it yet in NoSQL
    // unless we pre-fetched keys. We restrict to "Visited History" + "Next Available".
    // "Next Available" is currentPage + 1 if hasNextPage is true.

    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    for (let i = start; i <= end; i++) {
        // Only render if within reasonable bounds or previously visited
        if (i <= clickableLimit || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
