import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber', type: 'exact' },
  { label: 'Material', key: 'Material Number', type: 'exact' },
  { label: 'Sales Document', key: 'SalesDocument', type: 'exact' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (page: number, currentCursor: Cursor | null, searchParams: {field: string, text: string} | null) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      if (searchParams) {
        // --- SEARCH MODE ---
        let baseQuery = query(dbRef, orderByChild(searchParams.field));

        if (currentCursor) {
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- BROWSE MODE (Default) ---
        if (currentCursor) {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE));
        }
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const data = snapshot.val();
        let loadedOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // --- Post-Processing ---

        // Sort descending by date locally for display consistency
        loadedOrders.sort((a, b) => {
           const dateA = new Date(a.OrderDate || 0).getTime();
           const dateB = new Date(b.OrderDate || 0).getTime();
           return dateB - dateA;
        });

        // Handle Pagination Overlap
        if (currentCursor) {
           loadedOrders = loadedOrders.filter(o => o.Code !== currentCursor.key);
        }

        // Check for "Next Page" availability
        if (loadedOrders.length < PAGE_SIZE && currentCursor) {
            setHasNextPage(false);
        } else if (loadedOrders.length === 0) {
            setHasNextPage(false);
        } else {
            setHasNextPage(true);
        }

        setOrders(loadedOrders);

        // Prepare Cursor for Next Page
        if (loadedOrders.length > 0) {
           const lastItem = loadedOrders[loadedOrders.length - 1];
           const nextCursorValue = searchParams ? lastItem[searchParams.field] : lastItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: lastItem.Code });
             return newMap;
           });
        }

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      if (err.message && err.message.includes('index')) {
        setError(`Missing Index: Please add ".indexOn": ["OrderDate", "${searchField}"] to Firebase Rules.`);
      } else {
        setError(err.message || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    setCurrentPage(1);
    setCursorStack(new Map());
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    setStatusFilters(prev => 
      prev.includes(option) 
        ? prev.filter(f => f !== option)
        : [...prev, option]
    );
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    fetchOrders(currentPage, cursor, activeSearch);
  }, [currentPage, activeSearch]);

  // --- Client-Side Filtering ---

  const filteredOrders = orders.filter(order => {
    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    // OR Logic: Match ANY of the checked criteria
    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i <= clickableLimit || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Term</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Enter exact ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Clear
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Filter Status</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'All Statuses' 
                        : `${statusFilters.length} Selected`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 border-t border-slate-50 pt-2">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Reset Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {!searchMode && (
                    <div className="hidden xl:block text-xs text-slate-400 font-medium h-[42px] flex items-center">
                        Showing latest orders
                    </div>
                )}
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 
                        ? "No orders match the selected status filters on this page."
                        : searchMode 
                            ? `No exact matches found for "${activeSearch?.text}".` 
                            : "No orders found."}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {searchMode ? 'Search Results' : 'Sorting by Newest Date'} • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber', type: 'exact' },
  { label: 'Material', key: 'Material Number', type: 'exact' },
  { label: 'Sales Document', key: 'SalesDocument', type: 'exact' },
  { label: 'Status', key: 'Status', type: 'exact' } // Added Status for direct server-side querying
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (page: number, currentCursor: Cursor | null, searchParams: {field: string, text: string} | null) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      if (searchParams) {
        // --- SEARCH MODE ---
        let baseQuery = query(dbRef, orderByChild(searchParams.field));

        if (currentCursor) {
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
            q = query(baseQuery, equalTo(searchParams.text), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- BROWSE MODE (Default) ---
        if (currentCursor) {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE));
        }
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const data = snapshot.val();
        let loadedOrders: OrderRecord[] = Object.keys(data).map(key => ({
          ...data[key],
          Code: key
        }));

        // --- Post-Processing ---

        // Sort descending by date locally for display consistency
        loadedOrders.sort((a, b) => {
           const dateA = new Date(a.OrderDate || 0).getTime();
           const dateB = new Date(b.OrderDate || 0).getTime();
           return dateB - dateA;
        });

        // Handle Pagination Overlap
        if (currentCursor) {
           loadedOrders = loadedOrders.filter(o => o.Code !== currentCursor.key);
        }

        // Check for "Next Page" availability
        if (loadedOrders.length < PAGE_SIZE && currentCursor) {
            setHasNextPage(false);
        } else if (loadedOrders.length === 0) {
            setHasNextPage(false);
        } else {
            setHasNextPage(true);
        }

        setOrders(loadedOrders);

        // Prepare Cursor for Next Page
        if (loadedOrders.length > 0) {
           const lastItem = loadedOrders[loadedOrders.length - 1];
           const nextCursorValue = searchParams ? lastItem[searchParams.field] : lastItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: lastItem.Code });
             return newMap;
           });
        }

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      if (err.message && err.message.includes('index')) {
        setError(`Missing Index: Please add ".indexOn": ["OrderDate", "${searchField}"] to Firebase Rules.`);
      } else {
        setError(err.message || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    setCurrentPage(1);
    setCursorStack(new Map());
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    setStatusFilters(prev => 
      prev.includes(option) 
        ? prev.filter(f => f !== option)
        : [...prev, option]
    );
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    fetchOrders(currentPage, cursor, activeSearch);
  }, [currentPage, activeSearch]);

  // --- Client-Side Filtering ---

  const filteredOrders = orders.filter(order => {
    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    // OR Logic: Match ANY of the checked criteria
    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i <= clickableLimit || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Term</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Enter exact ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Clear
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Filter Visible Rows</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 border-t border-slate-50 pt-2">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Reset Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {!searchMode && (
                    <div className="hidden xl:block text-xs text-slate-400 font-medium h-[42px] flex items-center">
                        Showing latest orders
                    </div>
                )}
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No orders match your filters on this page.</p>
                            <p className="text-xs text-slate-400 max-w-xs mx-auto">
                                The current 50 orders loaded do not contain the selected statuses. 
                                Click below to scan the next 50 records.
                            </p>
                            {hasNextPage ? (
                                <button
                                    onClick={() => goToPage(currentPage + 1)}
                                    className="mt-2 px-4 py-2 bg-brand-50 text-brand-700 hover:bg-brand-100 rounded-lg text-sm font-semibold transition-colors border border-brand-200 flex items-center"
                                >
                                    Scan Next Page
                                    <svg className="w-4 h-4 ml-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                    </svg>
                                </button>
                            ) : (
                                <p className="text-xs text-slate-400 mt-2">End of data reached.</p>
                            )}
                        </div>
                     ) : searchMode ? (
                        `No exact matches found for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {searchMode ? 'Search Results' : 'Sorting by Newest Date'} • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, startAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber', type: 'exact' },
  { label: 'Material', key: 'Material Number', type: 'exact' },
  { label: 'Sales Document', key: 'SalesDocument', type: 'exact' },
  { label: 'Status', key: 'Status', type: 'exact' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (page: number, currentCursor: Cursor | null, searchParams: {field: string, text: string} | null) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      if (searchParams) {
        // --- SEARCH MODE ---
        // Pagination within exact matches requires combine startAt/endAt instead of equalTo
        const baseQuery = query(dbRef, orderByChild(searchParams.field));
        const val = searchParams.text;

        if (currentCursor) {
            // Next Pages: Constrain range to exact value, ending at cursor
            q = query(baseQuery, startAt(val), endAt(val, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
            // First Page: Simple equalTo is sufficient and cleaner
            q = query(baseQuery, equalTo(val), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- BROWSE MODE (Default) ---
        // Standard Reverse Pagination (Newest First)
        if (currentCursor) {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE));
        }
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        // 1. Convert snapshot to array preserving SERVER ORDER (Ascending)
        const rawOrders: OrderRecord[] = [];
        snapshot.forEach((child) => {
           rawOrders.push({ ...child.val(), Code: child.key as string });
        });

        // 2. Handle Pagination Overlap
        // Since we use limitToLast, the overlap item (cursor) is at the END of the result list (highest value/key)
        if (currentCursor) {
           const lastItem = rawOrders[rawOrders.length - 1];
           if (lastItem && lastItem.Code === currentCursor.key) {
               rawOrders.pop(); // Remove the overlap
           }
        }

        // 3. Determine Cursor for NEXT page
        // The "Next Page" (older data) starts before the FIRST item of this chunk (lowest value/key)
        if (rawOrders.length > 0) {
           const boundaryItem = rawOrders[0];
           const nextCursorValue = searchParams ? boundaryItem[searchParams.field] : boundaryItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: boundaryItem.Code });
             return newMap;
           });

           // If we got full page (or close to it), assume next page exists
           // Edge case: if exact multiple of PAGE_SIZE, next page might be empty.
           setHasNextPage(true);
        } else {
           setHasNextPage(false);
        }

        // 4. Sort for Display (Descending Date usually)
        // We clone to avoid mutating the cursor reference logic just in case
        const displayOrders = [...rawOrders].sort((a, b) => {
           const dateA = new Date(a.OrderDate || 0).getTime();
           const dateB = new Date(b.OrderDate || 0).getTime();
           return dateB - dateA; // Newest first
        });

        setOrders(displayOrders);

        // Double check empty result after overlap removal
        if (rawOrders.length === 0) {
            setHasNextPage(false);
        }

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      if (err.message && err.message.includes('index')) {
        setError(`Missing Index: Please add ".indexOn": ["OrderDate", "${searchField}"] to Firebase Rules.`);
      } else {
        setError(err.message || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    setCurrentPage(1);
    setCursorStack(new Map());
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber < 1) return;
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    // Only allow going to pages we have visited or the immediate next one
    // (In this simple stack, we can rely on the cursor existing for the requested page if we came from prev page)
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    } else {
        console.warn("Cursor missing for page", pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    setStatusFilters(prev => 
      prev.includes(option) 
        ? prev.filter(f => f !== option)
        : [...prev, option]
    );
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    // Safety check: if page > 1 but no cursor, force back to 1 (prevents getting stuck)
    if (currentPage > 1 && !cursor) {
        setCurrentPage(1);
        return;
    }
    fetchOrders(currentPage, cursor, activeSearch);
  }, [currentPage, activeSearch]);

  // --- Client-Side Filtering ---

  const filteredOrders = orders.filter(order => {
    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    // OR Logic: Match ANY of the checked criteria
    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    // Allow clicking next page if we suspect there is one
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        // We can navigate to page 1, or any page we have a cursor for
        if (i === 1 || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Term</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Enter exact ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Clear
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Filter Visible Rows</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 border-t border-slate-50 pt-2">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Reset Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {!searchMode && (
                    <div className="hidden xl:block text-xs text-slate-400 font-medium h-[42px] flex items-center">
                        Showing latest orders
                    </div>
                )}
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No orders match your filters on this page.</p>
                            <p className="text-xs text-slate-400 max-w-xs mx-auto">
                                The current 50 orders loaded do not contain the selected statuses. 
                                Click below to scan the next 50 records.
                            </p>
                            {hasNextPage ? (
                                <button
                                    onClick={() => goToPage(currentPage + 1)}
                                    className="mt-2 px-4 py-2 bg-brand-50 text-brand-700 hover:bg-brand-100 rounded-lg text-sm font-semibold transition-colors border border-brand-200 flex items-center"
                                >
                                    Scan Next Page
                                    <svg className="w-4 h-4 ml-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                    </svg>
                                </button>
                            ) : (
                                <p className="text-xs text-slate-400 mt-2">End of data reached.</p>
                            )}
                        </div>
                     ) : searchMode ? (
                        `No exact matches found for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {searchMode ? 'Search Results' : 'Sorting by Newest Date'} • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, startAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber', type: 'exact' },
  { label: 'Material', key: 'Material Number', type: 'exact' },
  { label: 'Sales Document', key: 'SalesDocument', type: 'exact' },
  { label: 'Status', key: 'Status', type: 'exact' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (
      page: number, 
      currentCursor: Cursor | null, 
      searchParams: {field: string, text: string} | null,
      activeFilters: string[]
  ) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // Determine Query Mode
      // We use Server-Side Query if:
      // 1. User performed a specific Search
      // 2. OR User selected exactly ONE status filter (and it's not a negation like "Not shipped")
      // This optimization allows us to "Find" the rows in the DB instead of just filtering the current page.

      const singleStatusFilter = (!searchParams && activeFilters.length === 1 && activeFilters[0] !== 'Not shipped') 
        ? activeFilters[0] 
        : null;

      if (searchParams || singleStatusFilter) {
        // --- TARGETED QUERY MODE ---
        const field = searchParams ? searchParams.field : 'Status';
        const val = searchParams ? searchParams.text : singleStatusFilter!;

        const baseQuery = query(dbRef, orderByChild(field));

        if (currentCursor) {
            // Next Pages:
            // Range: Start at 'val', End at Cursor (inclusive descending)
            // This works for both Exact Match and StartsWith because cursor defines the upper bound of the "remaining" data
            q = query(baseQuery, startAt(val), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
            // First Page:
            // If it's a Status filter, we want "Starts With" logic (e.g. "Shipped" matches "Shipped - 123")
            // We use endAt(val + "\uf8ff") to include all suffixes.
            // If it's exact search, this also works safely.
            q = query(baseQuery, startAt(val), endAt(val + "\uf8ff"), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- BROWSE MODE (Default) ---
        // Sort by Date Descending
        if (currentCursor) {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE + 1), endAt(currentCursor.value, currentCursor.key));
        } else {
           q = query(dbRef, orderByChild('OrderDate'), limitToLast(PAGE_SIZE));
        }
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        // 1. Convert snapshot to array preserving SERVER ORDER (Ascending)
        const rawOrders: OrderRecord[] = [];
        snapshot.forEach((child) => {
           rawOrders.push({ ...child.val(), Code: child.key as string });
        });

        // 2. Handle Pagination Overlap
        if (currentCursor) {
           const lastItem = rawOrders[rawOrders.length - 1];
           if (lastItem && lastItem.Code === currentCursor.key) {
               rawOrders.pop(); 
           }
        }

        // 3. Determine Cursor for NEXT page
        if (rawOrders.length > 0) {
           const boundaryItem = rawOrders[0];

           let nextCursorValue;
           if (searchParams) nextCursorValue = boundaryItem[searchParams.field];
           else if (singleStatusFilter) nextCursorValue = boundaryItem['Status'];
           else nextCursorValue = boundaryItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: boundaryItem.Code });
             return newMap;
           });
           setHasNextPage(true);
        } else {
           setHasNextPage(false);
        }

        // 4. Sort for Display (Descending Date usually)
        const displayOrders = [...rawOrders].sort((a, b) => {
           const dateA = new Date(a.OrderDate || 0).getTime();
           const dateB = new Date(b.OrderDate || 0).getTime();
           return dateB - dateA; 
        });

        setOrders(displayOrders);

        if (rawOrders.length === 0) setHasNextPage(false);

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      // Helper for missing index error which is common when adding new sort fields
      const msg = err.message || '';
      if (msg.includes('index')) {
        const field = searchParams?.field || (statusFilters.length === 1 ? 'Status' : 'OrderDate');
        setError(`Database Error: Missing Index on "${field}". Please update Firebase Rules.`);
      } else {
        setError(msg || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    setCurrentPage(1);
    setCursorStack(new Map());
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
    // Clear status filters to avoid conflict visually
    setStatusFilters([]); 
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber < 1) return;
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    setStatusFilters(prev => {
        const newFilters = prev.includes(option) 
        ? prev.filter(f => f !== option)
        : [...prev, option];

        // IMPORTANT: Reset pagination when filter changes to trigger fresh fetch
        setCurrentPage(1);
        setCursorStack(new Map());
        return newFilters;
    });
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    if (currentPage > 1 && !cursor) {
        setCurrentPage(1);
        return;
    }
    fetchOrders(currentPage, cursor, activeSearch, statusFilters);
  }, [currentPage, activeSearch, statusFilters]);

  // --- Client-Side Filtering ---
  // Even though we might have fetched based on status, we still apply this to handle
  // "Not shipped" logic or multiple selection logic if we fell back to Browse Mode.

  const filteredOrders = orders.filter(order => {
    if (statusFilters.length === 0) return true;

    // Optimization: If we already server-filtered for this single status, 
    // we can skip strict checking or just let it pass (it will match anyway).
    // However, keeping it ensures consistency if DB has mixed casing.

    const s = (order.Status || '').toLowerCase();

    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i === 1 || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  const isServerSideFilterActive = !activeSearch && statusFilters.length === 1 && statusFilters[0] !== 'Not shipped';

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Term</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Enter exact ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Clear
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Filter Visible Rows</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 border-t border-slate-50 pt-2">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Reset Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {!searchMode && (
                    <div className="hidden xl:block text-xs text-slate-400 font-medium h-[42px] flex items-center">
                        {isServerSideFilterActive 
                            ? `Filtered by "${statusFilters[0]}"` 
                            : 'Showing latest orders'
                        }
                    </div>
                )}
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No orders found matching: {statusFilters.join(', ')}</p>
                            {statusFilters.length > 1 && (
                                <p className="text-xs text-slate-400">
                                   Tip: Select a single status to search the entire database.
                                </p>
                            )}
                        </div>
                     ) : searchMode ? (
                        `No exact matches found for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {isServerSideFilterActive
                    ? 'Sorting by matched Status' 
                    : searchMode ? 'Search Results' : 'Sorting by Newest Date'
                 } • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, startAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (
      page: number, 
      currentCursor: Cursor | null, 
      searchParams: {field: string, text: string} | null,
      activeFilters: string[]
  ) => {
    setLoading(true);
    setError(null);

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // --- LOGIC: Server-Side Priority ---
      // 1. Specific Search Text takes highest priority.
      // 2. Single Status Filter takes second priority (switches sort to 'Status').
      // 3. Default: Sort by OrderDate.

      const isSingleStatusFilter = !searchParams && activeFilters.length === 1 && activeFilters[0] !== 'Not shipped';

      if (searchParams) {
        // --- MODE A: Text Search (Server-Side) ---
        // Queries specific field (e.g., OrderNumber) for the text string.

        const field = searchParams.field;
        const val = searchParams.text;

        // We use startAt/endAt to emulate "StartsWith" logic, allowing partial matches at the beginning
        // or exact matches.
        const baseQuery = query(dbRef, orderByChild(field));

        if (currentCursor) {
            // Pagination: Keep constraints but start AFTER the last known item (via cursor)
            // Note: In firebase, reverse pagination with searching is tricky. 
            // We use limitToLast to get "relevance" or "newest" if keys correlate, 
            // but for exact text search, limitToFirst might be more intuitive. 
            // However, sticking to limitToLast to maintain architecture consistency.
            q = query(baseQuery, startAt(val), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
            // First Page
            q = query(baseQuery, startAt(val), endAt(val + "\uf8ff"), limitToLast(PAGE_SIZE));
        }

      } else if (isSingleStatusFilter) {
        // --- MODE B: Status Filter (Server-Side) ---
        // Queries 'Status' field directly. This enables scanning the WHOLE DB for 'Shipped'.

        const statusToFind = activeFilters[0];
        const baseQuery = query(dbRef, orderByChild('Status'));

        if (currentCursor) {
           // Paginate within the specific status
           q = query(baseQuery, equalTo(statusToFind), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           q = query(baseQuery, equalTo(statusToFind), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- MODE C: Browse / Default (Server-Side) ---
        // Sorts by Date. (Client-side filtering applies here for "Not shipped" or complex filters)

        const baseQuery = query(dbRef, orderByChild('OrderDate'));

        if (currentCursor) {
           q = query(baseQuery, endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           q = query(baseQuery, limitToLast(PAGE_SIZE));
        }
      }

      // Execute Query
      const snapshot = await get(q);

      if (snapshot.exists()) {
        const rawOrders: OrderRecord[] = [];
        // Snapshot returns data in ascending order of the Sorted Key.
        snapshot.forEach((child) => {
           rawOrders.push({ ...child.val(), Code: child.key as string });
        });

        // Handle Pagination Overlap (Remove the cursor item from previous page)
        if (currentCursor) {
           const lastItem = rawOrders[rawOrders.length - 1];
           if (lastItem && lastItem.Code === currentCursor.key) {
               rawOrders.pop(); 
           }
        }

        // Determine Cursor for NEXT page
        if (rawOrders.length > 0) {
           const boundaryItem = rawOrders[0]; // The 'oldest' item in this batch (since we used limitToLast)

           let nextCursorValue;
           if (searchParams) nextCursorValue = boundaryItem[searchParams.field];
           else if (isSingleStatusFilter) nextCursorValue = boundaryItem['Status'];
           else nextCursorValue = boundaryItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: boundaryItem.Code });
             return newMap;
           });
           setHasNextPage(true);
        } else {
           setHasNextPage(false);
        }

        // Sort for Display
        // We always want to show the "Newest" or "Most Relevant" at the top of the table.
        // Since we fetched via limitToLast (Ascending from DB), we reverse it.
        const displayOrders = [...rawOrders].reverse();

        setOrders(displayOrders);

        if (rawOrders.length === 0) setHasNextPage(false);

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      const msg = err.message || '';
      if (msg.includes('index')) {
        const field = searchParams?.field || (isSingleStatusFilter ? 'Status' : 'OrderDate');
        setError(`Database Error: Missing Index on "${field}". Add ".indexOn": ["${field}"] to Firebase Rules.`);
      } else {
        setError(msg || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    // Reset pagination and filters to ensure clean search
    setCurrentPage(1);
    setCursorStack(new Map());
    setStatusFilters([]); 
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber < 1) return;
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    // When a filter is toggled, we reset everything to Page 1.
    // This allows the fetchOrders logic to pick up the new "Single Filter" mode if applicable.

    setStatusFilters(prev => {
        let newFilters;
        if (prev.includes(option)) {
            newFilters = prev.filter(f => f !== option);
        } else {
            // UX Decision: For server-side filtering to work best, we often want single select.
            // However, allowing multi-select is standard. 
            // Our fetchOrders optimizes for length === 1.
            newFilters = [...prev, option];
        }

        setCurrentPage(1);
        setCursorStack(new Map());
        return newFilters;
    });
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    if (currentPage > 1 && !cursor) {
        setCurrentPage(1);
        return;
    }
    fetchOrders(currentPage, cursor, activeSearch, statusFilters);
  }, [currentPage, activeSearch, statusFilters]);

  // --- Client-Side Filtering (Secondary Layer) ---
  // This handles complex cases (e.g., "Not shipped" or multiple statuses selected)
  // where the server query might have returned a broader set (like by Date).

  const filteredOrders = orders.filter(order => {
    // If we are in "Single Status Mode" (Server Filter), the data is already filtered.
    // But we double check here safely.

    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i === 1 || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  // Determine active mode for UI display
  const isServerFilterActive = !activeSearch && statusFilters.length === 1 && statusFilters[0] !== 'Not shipped';
  const isBrowseMode = !activeSearch && !isServerFilterActive;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Database By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Enter Value</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Find ${SEARCH_FIELDS.find(f => f.key === searchField)?.label} in DB...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search DB
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status Filter</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'All Statuses' 
                        : `${statusFilters.length} Selected`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      <div className="px-2 pb-2 pt-1 border-t border-slate-50 text-[10px] text-slate-400 text-center">
                        Select one to search server
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 pt-1">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Clear Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <div className="hidden xl:block text-xs font-medium h-[42px] flex items-center">
                    {activeSearch && (
                        <span className="text-brand-600 bg-brand-50 px-2 py-1 rounded border border-brand-100">
                             Found results for "{activeSearch.text}"
                        </span>
                    )}
                    {isServerFilterActive && (
                        <span className="text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100">
                             Database Filter: {statusFilters[0]}
                        </span>
                    )}
                    {isBrowseMode && (
                        <span className="text-slate-400">Showing Latest</span>
                    )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No results found.</p>
                            <p className="text-xs text-slate-400">
                               {isServerFilterActive 
                                 ? `The database contains no orders with status "${statusFilters[0]}".`
                                 : `No orders match your current filters.`}
                            </p>
                        </div>
                     ) : searchMode ? (
                        `No exact matches found in database for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {isServerFilterActive
                    ? `Sorting by Status (${statusFilters[0]})`
                    : searchMode ? 'Database Search Results' : 'Sorting by Newest Date'
                 } • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, startAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (
      page: number, 
      currentCursor: Cursor | null, 
      searchParams: {field: string, text: string} | null,
      activeFilters: string[]
  ) => {
    setLoading(true);
    setError(null);

    // --- LOGIC: Server-Side Priority ---
    // 1. Specific Search Text takes highest priority.
    // 2. Single Status Filter takes second priority (switches sort to 'Status').
    // 3. Default: Sort by OrderDate.
    const isSingleStatusFilter = !searchParams && activeFilters.length === 1 && activeFilters[0] !== 'Not shipped';

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      if (searchParams) {
        // --- MODE A: Text Search (Server-Side) ---
        // Queries specific field (e.g., OrderNumber) for the text string.

        const field = searchParams.field;
        const val = searchParams.text;

        // We use startAt/endAt to emulate "StartsWith" logic, allowing partial matches at the beginning
        // or exact matches.
        const baseQuery = query(dbRef, orderByChild(field));

        if (currentCursor) {
            // Pagination: Keep constraints but start AFTER the last known item (via cursor)
            // Note: In firebase, reverse pagination with searching is tricky. 
            // We use limitToLast to get "relevance" or "newest" if keys correlate, 
            // but for exact text search, limitToFirst might be more intuitive. 
            // However, sticking to limitToLast to maintain architecture consistency.
            q = query(baseQuery, startAt(val), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
            // First Page
            q = query(baseQuery, startAt(val), endAt(val + "\uf8ff"), limitToLast(PAGE_SIZE));
        }

      } else if (isSingleStatusFilter) {
        // --- MODE B: Status Filter (Server-Side) ---
        // Queries 'Status' field directly. This enables scanning the WHOLE DB for 'Shipped'.

        const statusToFind = activeFilters[0];
        const baseQuery = query(dbRef, orderByChild('Status'));

        if (currentCursor) {
           // Paginate within the specific status
           q = query(baseQuery, equalTo(statusToFind), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           q = query(baseQuery, equalTo(statusToFind), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- MODE C: Browse / Default (Server-Side) ---
        // Sorts by Date. (Client-side filtering applies here for "Not shipped" or complex filters)

        const baseQuery = query(dbRef, orderByChild('OrderDate'));

        if (currentCursor) {
           q = query(baseQuery, endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           q = query(baseQuery, limitToLast(PAGE_SIZE));
        }
      }

      // Execute Query
      const snapshot = await get(q);

      if (snapshot.exists()) {
        const rawOrders: OrderRecord[] = [];
        // Snapshot returns data in ascending order of the Sorted Key.
        snapshot.forEach((child) => {
           rawOrders.push({ ...child.val(), Code: child.key as string });
        });

        // Handle Pagination Overlap (Remove the cursor item from previous page)
        if (currentCursor) {
           const lastItem = rawOrders[rawOrders.length - 1];
           if (lastItem && lastItem.Code === currentCursor.key) {
               rawOrders.pop(); 
           }
        }

        // Determine Cursor for NEXT page
        if (rawOrders.length > 0) {
           const boundaryItem = rawOrders[0]; // The 'oldest' item in this batch (since we used limitToLast)

           let nextCursorValue;
           if (searchParams) nextCursorValue = boundaryItem[searchParams.field];
           else if (isSingleStatusFilter) nextCursorValue = boundaryItem['Status'];
           else nextCursorValue = boundaryItem.OrderDate;

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue, key: boundaryItem.Code });
             return newMap;
           });
           setHasNextPage(true);
        } else {
           setHasNextPage(false);
        }

        // Sort for Display
        // We always want to show the "Newest" or "Most Relevant" at the top of the table.
        // Since we fetched via limitToLast (Ascending from DB), we reverse it.
        const displayOrders = [...rawOrders].reverse();

        setOrders(displayOrders);

        if (rawOrders.length === 0) setHasNextPage(false);

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      const msg = err.message || '';
      if (msg.includes('index')) {
        const field = searchParams?.field || (isSingleStatusFilter ? 'Status' : 'OrderDate');
        setError(`Database Error: Missing Index on "${field}". Add ".indexOn": ["${field}"] to Firebase Rules.`);
      } else {
        setError(msg || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    // Reset pagination and filters to ensure clean search
    setCurrentPage(1);
    setCursorStack(new Map());
    setStatusFilters([]); 
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber < 1) return;
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    // When a filter is toggled, we reset everything to Page 1.
    // This allows the fetchOrders logic to pick up the new "Single Filter" mode if applicable.

    setStatusFilters(prev => {
        let newFilters;
        if (prev.includes(option)) {
            newFilters = prev.filter(f => f !== option);
        } else {
            // UX Decision: For server-side filtering to work best, we often want single select.
            // However, allowing multi-select is standard. 
            // Our fetchOrders optimizes for length === 1.
            newFilters = [...prev, option];
        }

        setCurrentPage(1);
        setCursorStack(new Map());
        return newFilters;
    });
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    if (currentPage > 1 && !cursor) {
        setCurrentPage(1);
        return;
    }
    fetchOrders(currentPage, cursor, activeSearch, statusFilters);
  }, [currentPage, activeSearch, statusFilters]);

  // --- Client-Side Filtering (Secondary Layer) ---
  // This handles complex cases (e.g., "Not shipped" or multiple statuses selected)
  // where the server query might have returned a broader set (like by Date).

  const filteredOrders = orders.filter(order => {
    // If we are in "Single Status Mode" (Server Filter), the data is already filtered.
    // But we double check here safely.

    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];
    const clickableLimit = hasNextPage ? currentPage + 1 : currentPage;

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i === 1 || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  // Determine active mode for UI display
  const isServerFilterActive = !activeSearch && statusFilters.length === 1 && statusFilters[0] !== 'Not shipped';
  const isBrowseMode = !activeSearch && !isServerFilterActive;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Database By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Enter Value</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Find ${SEARCH_FIELDS.find(f => f.key === searchField)?.label} in DB...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search DB
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status Filter</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'All Statuses' 
                        : `${statusFilters.length} Selected`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      <div className="px-2 pb-2 pt-1 border-t border-slate-50 text-[10px] text-slate-400 text-center">
                        Select one to search server
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 pt-1">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Clear Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <div className="hidden xl:block text-xs font-medium h-[42px] flex items-center">
                    {activeSearch && (
                        <span className="text-brand-600 bg-brand-50 px-2 py-1 rounded border border-brand-100">
                             Found results for "{activeSearch.text}"
                        </span>
                    )}
                    {isServerFilterActive && (
                        <span className="text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100">
                             Database Filter: {statusFilters[0]}
                        </span>
                    )}
                    {isBrowseMode && (
                        <span className="text-slate-400">Showing Latest</span>
                    )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No results found.</p>
                            <p className="text-xs text-slate-400">
                               {isServerFilterActive 
                                 ? `The database contains no orders with status "${statusFilters[0]}".`
                                 : `No orders match your current filters.`}
                            </p>
                        </div>
                     ) : searchMode ? (
                        `No exact matches found in database for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {isServerFilterActive
                    ? `Sorting by Status (${statusFilters[0]})`
                    : searchMode ? 'Database Search Results' : 'Sorting by Newest Date'
                 } • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt, equalTo, startAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

// Search Field Mapping
const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' }
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface Cursor {
  value: string | number;
  key: string;
}

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- State Management ---
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search State
  const [searchMode, setSearchMode] = useState(false);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [activeSearch, setActiveSearch] = useState<{field: string, text: string} | null>(null);

  // Filter State
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [cursorStack, setCursorStack] = useState<Map<number, Cursor | null>>(new Map());
  const [hasNextPage, setHasNextPage] = useState(true);

  // --- Data Fetching Logic ---

  const fetchOrders = async (
      page: number, 
      currentCursor: Cursor | null, 
      searchParams: {field: string, text: string} | null,
      activeFilters: string[]
  ) => {
    setLoading(true);
    setError(null);

    // --- LOGIC: Server-Side Priority ---
    // 1. Specific Search Text takes highest priority.
    // 2. Single Status Filter takes second priority (switches sort to 'Status').
    // 3. Default: Sort by OrderDate.
    const isSingleStatusFilter = !searchParams && activeFilters.length === 1 && activeFilters[0] !== 'Not shipped';

    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      if (searchParams) {
        // --- MODE A: Text Search (Server-Side) ---
        // Queries specific field (e.g., OrderNumber) for the text string.

        const field = searchParams.field;
        const val = searchParams.text;

        // We use startAt/endAt to emulate "StartsWith" logic.
        const baseQuery = query(dbRef, orderByChild(field));

        if (currentCursor) {
            q = query(baseQuery, startAt(val), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
            q = query(baseQuery, startAt(val), endAt(val + "\uf8ff"), limitToLast(PAGE_SIZE));
        }

      } else if (isSingleStatusFilter) {
        // --- MODE B: Status Filter (Server-Side) ---
        // Changed to use startAt/endAt instead of equalTo.
        // This is more robust against trailing spaces or slight variations in DB data.

        const statusToFind = activeFilters[0];
        const baseQuery = query(dbRef, orderByChild('Status'));

        if (currentCursor) {
           // Paginate within the specific status range
           q = query(baseQuery, startAt(statusToFind), endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           // First Page: Find all items starting with the status string
           q = query(baseQuery, startAt(statusToFind), endAt(statusToFind + "\uf8ff"), limitToLast(PAGE_SIZE));
        }

      } else {
        // --- MODE C: Browse / Default (Server-Side) ---
        // Sorts by Date. (Client-side filtering applies here for "Not shipped" or complex filters)

        const baseQuery = query(dbRef, orderByChild('OrderDate'));

        if (currentCursor) {
           q = query(baseQuery, endAt(currentCursor.value, currentCursor.key), limitToLast(PAGE_SIZE + 1));
        } else {
           q = query(baseQuery, limitToLast(PAGE_SIZE));
        }
      }

      // Execute Query
      const snapshot = await get(q);

      if (snapshot.exists()) {
        const rawOrders: OrderRecord[] = [];
        // Snapshot returns data in ascending order of the Sorted Key.
        snapshot.forEach((child) => {
           rawOrders.push({ ...child.val(), Code: child.key as string });
        });

        // Handle Pagination Overlap (Remove the cursor item from previous page)
        if (currentCursor) {
           const lastItem = rawOrders[rawOrders.length - 1];
           if (lastItem && lastItem.Code === currentCursor.key) {
               rawOrders.pop(); 
           }
        }

        // Determine Cursor for NEXT page
        if (rawOrders.length > 0) {
           const boundaryItem = rawOrders[0]; // The 'oldest' item in this batch (since we used limitToLast)

           let nextCursorValue;
           // Safe Access with Fallbacks
           if (searchParams) {
              nextCursorValue = boundaryItem[searchParams.field];
              if (nextCursorValue === undefined) nextCursorValue = ''; 
           } else if (isSingleStatusFilter) {
              nextCursorValue = boundaryItem['Status'];
              if (nextCursorValue === undefined) nextCursorValue = '';
           } else {
              nextCursorValue = boundaryItem.OrderDate;
              if (nextCursorValue === undefined) nextCursorValue = '';
           }

           setCursorStack(prev => {
             const newMap = new Map(prev);
             newMap.set(page + 1, { value: nextCursorValue!, key: boundaryItem.Code });
             return newMap;
           });
           setHasNextPage(true);
        } else {
           setHasNextPage(false);
        }

        // Sort for Display
        // We always want to show the "Newest" or "Most Relevant" at the top of the table.
        // Since we fetched via limitToLast (Ascending from DB), we reverse it.
        const displayOrders = [...rawOrders].reverse();

        setOrders(displayOrders);

        if (rawOrders.length === 0) setHasNextPage(false);

      } else {
        setOrders([]);
        setHasNextPage(false);
      }

    } catch (err: any) {
      console.error("Data Load Error:", err);
      const msg = err.message || '';
      if (msg.includes('index')) {
        const field = searchParams?.field || (isSingleStatusFilter ? 'Status' : 'OrderDate');
        setError(`Database Error: Missing Index on "${field}". Add ".indexOn": ["${field}"] to Firebase Rules.`);
      } else {
        setError(msg || 'Unknown error occurred');
      }
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchText.trim()) return;

    // Reset pagination and filters to ensure clean search
    setCurrentPage(1);
    setCursorStack(new Map());
    setStatusFilters([]); 
    setActiveSearch({ field: searchField, text: searchText.trim() });
    setSearchMode(true);
  };

  const clearSearch = () => {
    setSearchText('');
    setSearchMode(false);
    setActiveSearch(null);
    setCurrentPage(1);
    setCursorStack(new Map());
  };

  const goToPage = (pageNumber: number) => {
    if (pageNumber < 1) return;
    if (pageNumber === 1) {
        setCurrentPage(1);
        return;
    }
    const cursor = cursorStack.get(pageNumber);
    if (cursor) {
        setCurrentPage(pageNumber);
    }
  };

  const toggleFilter = (option: string) => {
    // When a filter is toggled, we reset everything to Page 1.
    // This allows the fetchOrders logic to pick up the new "Single Filter" mode if applicable.

    setStatusFilters(prev => {
        let newFilters;
        if (prev.includes(option)) {
            newFilters = prev.filter(f => f !== option);
        } else {
            // UX Decision: For server-side filtering to work best, we often want single select.
            // However, allowing multi-select is standard. 
            // Our fetchOrders optimizes for length === 1.
            newFilters = [...prev, option];
        }

        setCurrentPage(1);
        setCursorStack(new Map());
        return newFilters;
    });
  };

  // Close filter dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // --- Effects ---

  useEffect(() => {
    const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
    if (currentPage > 1 && !cursor) {
        setCurrentPage(1);
        return;
    }
    fetchOrders(currentPage, cursor, activeSearch, statusFilters);
  }, [currentPage, activeSearch, statusFilters]);

  // --- Client-Side Filtering (Secondary Layer) ---
  // This handles complex cases (e.g., "Not shipped" or multiple statuses selected)
  // where the server query might have returned a broader set (like by Date).

  const filteredOrders = orders.filter(order => {
    // If we are in "Single Status Mode" (Server Filter), the data is already filtered.
    // But we double check here safely.

    if (statusFilters.length === 0) return true;

    const s = (order.Status || '').toLowerCase();

    return statusFilters.some(filter => {
      if (filter === 'Shipped') return s.includes('shipped');
      if (filter === 'Canceled') return s.includes('canceled');
      if (filter === 'Duplicate') return s.includes('duplicate');
      if (filter === 'PA') return s.includes('pa');
      if (filter === 'Not shipped') return !s.includes('shipped');
      return false;
    });
  });

  // --- Render Helpers ---

  const renderPaginationNumbers = () => {
    const pages = [];

    let start = Math.max(1, currentPage - 2);
    let end = Math.max(start + 4, currentPage + 1);

    for (let i = start; i <= end; i++) {
        if (i === 1 || cursorStack.has(i)) {
             pages.push(
                <button
                    key={i}
                    onClick={() => goToPage(i)}
                    className={`w-8 h-8 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                        currentPage === i 
                        ? 'bg-brand-600 text-white shadow-md' 
                        : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200'
                    }`}
                >
                    {i}
                </button>
             );
        }
    }
    return pages;
  };

  // Determine active mode for UI display
  const isServerFilterActive = !activeSearch && statusFilters.length === 1 && statusFilters[0] !== 'Not shipped';
  const isBrowseMode = !activeSearch && !isServerFilterActive;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                {/* Search Type Selector */}
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search Database By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        disabled={loading}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                {/* Search Input */}
                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Enter Value</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Find ${SEARCH_FIELDS.find(f => f.key === searchField)?.label} in DB...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none shadow-inner"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                {/* Actions: Search & Clear */}
                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading || !searchText}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Search DB
                    </button>

                    {searchMode && (
                        <button 
                            type="button"
                            onClick={clearSearch}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters & Status */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                {/* Filter Dropdown */}
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status Filter</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'All Statuses' 
                        : `${statusFilters.length} Selected`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {/* Dropdown Menu */}
                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                      <div className="px-2 pb-2 pt-1 border-t border-slate-50 text-[10px] text-slate-400 text-center">
                        Select one to search server
                      </div>
                      {statusFilters.length > 0 && (
                        <div className="px-2 pb-2 pt-1">
                           <button
                             type="button"
                             onClick={() => setStatusFilters([])}
                             className="w-full text-center text-xs text-brand-600 hover:text-brand-800 font-medium py-1"
                           >
                             Clear Filters
                           </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <div className="hidden xl:block text-xs font-medium h-[42px] flex items-center">
                    {activeSearch && (
                        <span className="text-brand-600 bg-brand-50 px-2 py-1 rounded border border-brand-100">
                             Found results for "{activeSearch.text}"
                        </span>
                    )}
                    {isServerFilterActive && (
                        <span className="text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100">
                             Database Filter: {statusFilters[0]}
                        </span>
                    )}
                    {isBrowseMode && (
                        <span className="text-slate-400">Showing Latest</span>
                    )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Optimized Column Widths */}
            <colgroup>
              <col className="w-28" /> {/* Order # */}
              <col className="w-28" /> {/* Sales Doc */}
              <col className="w-28" /> {/* Date */}
              <col className="w-24" /> {/* Batch */}
              <col className="w-16" /> {/* Year */}
              <col className="w-96" /> {/* Material - Wide */}
              <col className="w-40" /> {/* Club */}
              <col className="w-24" /> {/* Type */}
              <col className="w-32" /> {/* Status */}
              <col className="w-24" /> {/* CDD */}
              <col className="w-40" /> {/* UPS */}
              {isAdmin && <col className="w-20" />} {/* Action */}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center">
                      <div className="inline-flex flex-col items-center p-4 rounded-lg bg-red-50 text-red-700 border border-red-100 max-w-md mx-auto">
                         <div className="flex items-center font-bold mb-2">
                           <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                           Database Error
                         </div>
                         <span className="text-sm">{error}</span>
                      </div>
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex justify-center items-center gap-2">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    </div>
                 </td></tr>
              ) : filteredOrders.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {statusFilters.length > 0 ? (
                        <div className="flex flex-col items-center justify-center gap-3">
                            <p className="text-slate-600 font-medium">No results found.</p>
                            <p className="text-xs text-slate-400">
                               {isServerFilterActive 
                                 ? `The database contains no orders starting with status "${statusFilters[0]}".`
                                 : `No orders match your current filters.`}
                            </p>
                        </div>
                     ) : searchMode ? (
                        `No exact matches found in database for "${activeSearch?.text}".` 
                     ) : (
                        "No orders found."
                     )}
                   </td>
                 </tr>
              ) : (
                filteredOrders.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>

                      {/* Material Column: Priority Visibility */}
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           {/* Custom Tooltip */}
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                              <div className="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                           </div>
                        </div>
                      </td>

                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {!error && orders.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">

               <div className="text-xs text-slate-500 font-medium">
                 {isServerFilterActive
                    ? `Sorting by Status (${statusFilters[0]})`
                    : searchMode ? 'Database Search Results' : 'Sorting by Newest Date'
                 } • Page {currentPage}
               </div>

               <div className="flex items-center gap-2">
                 <button
                    onClick={() => goToPage(currentPage - 1)}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Previous
                 </button>

                 <div className="flex items-center gap-1 px-2">
                    {renderPaginationNumbers()}
                 </div>

                 <button
                    onClick={() => goToPage(currentPage + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                 >
                    Next
                 </button>
               </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' },
  { label: 'Status', key: 'Status' } 
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- Modes ---
  // BROWSE: Server-side pagination (Efficient for initial load)
  // SEARCH: Client-side filtering of full dataset (Robust for substring/multi-field search)
  const [mode, setMode] = useState<'BROWSE' | 'SEARCH'>('BROWSE');

  // --- State ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Browse Mode State
  const [browseOrders, setBrowseOrders] = useState<OrderRecord[]>([]);
  const [cursorStack, setCursorStack] = useState<Map<number, {value: any, key: string} | null>>(new Map());
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(true);

  // Search Mode State
  const [allData, setAllData] = useState<OrderRecord[]>([]); // Cache for search
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);

  // UI State
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // --- 1. Browse Mode Logic (Server Side) ---

  const fetchBrowsePage = async (page: number, cursor: {value: any, key: string} | null) => {
    setLoading(true);
    setError(null);
    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // Default Browse: Sort by OrderDate Descending
      // Firebase sorts Ascending, so we use limitToLast
      const baseQuery = query(dbRef, orderByChild('OrderDate'));

      if (cursor) {
        // Get previous page relative to cursor
        q = query(baseQuery, endAt(cursor.value, cursor.key), limitToLast(PAGE_SIZE + 1));
      } else {
        // Get first page (latest dates)
        q = query(baseQuery, limitToLast(PAGE_SIZE));
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const raw: OrderRecord[] = [];
        snapshot.forEach(c => raw.push({ ...c.val(), Code: c.key as string }));

        // Handle Overlap
        if (cursor) {
           const last = raw[raw.length - 1];
           if (last && last.Code === cursor.key) raw.pop();
        }

        // Determine Next Cursor (Oldest item in this batch, since it's limitToLast)
        if (raw.length > 0) {
            const boundary = raw[0];
            setCursorStack(prev => {
                const map = new Map(prev);
                map.set(page + 1, { value: boundary.OrderDate, key: boundary.Code });
                return map;
            });
            setHasNextPage(true);
        } else {
            setHasNextPage(false);
        }

        // Reverse to show Newest First
        setBrowseOrders(raw.reverse());
        if (raw.length === 0) setHasNextPage(false);

      } else {
        setBrowseOrders([]);
        setHasNextPage(false);
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === 'BROWSE') {
        const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
        fetchBrowsePage(currentPage, cursor);
    }
  }, [mode, currentPage]); // Remove cursorStack dependency to avoid loops

  // --- 2. Search Mode Logic (Client Side "Deep Search") ---

  const initSearch = async () => {
    setLoading(true);
    setError(null);
    try {
        // Fetch ALL data for robust filtering. 
        // Note: For very large datasets (>20k rows), consider cloud functions. 
        // For <10k rows, this is fast and provides the best UX for "contains" search.
        const dbRef = ref(db, 'order_management/master_recon_file');
        // We order by Date just to have a deterministic initial sort
        const snapshot = await get(query(dbRef, orderByChild('OrderDate'))); 

        if (snapshot.exists()) {
            const fullList: OrderRecord[] = [];
            snapshot.forEach(c => fullList.push({ ...c.val(), Code: c.key as string }));
            // Default sort: Newest first
            fullList.reverse();
            setAllData(fullList);
            setMode('SEARCH');
            setCurrentPage(1); // Reset to page 1 of search results
        } else {
            setAllData([]);
            setMode('SEARCH');
        }
    } catch (err: any) {
        console.error(err);
        setError("Failed to search database. Please try again.");
    } finally {
        setLoading(false);
    }
  };

  // Derived State for Search Results
  const searchResults = useMemo(() => {
    if (mode !== 'SEARCH') return [];

    return allData.filter(order => {
        // 1. Text Search
        if (searchText.trim()) {
            const val = order[searchField];
            if (!val) return false;

            // Substring Match (Case Insensitive)
            if (!String(val).toLowerCase().includes(searchText.toLowerCase())) {
                return false;
            }
        }

        // 2. Status Filter
        if (statusFilters.length > 0) {
            const s = (order.Status || '').toLowerCase();
            const matches = statusFilters.some(filter => {
                if (filter === 'Shipped') return s.includes('shipped');
                if (filter === 'Canceled') return s.includes('canceled');
                if (filter === 'Duplicate') return s.includes('duplicate');
                if (filter === 'PA') return s.includes('pa');
                if (filter === 'Not shipped') return !s.includes('shipped');
                return false;
            });
            if (!matches) return false;
        }

        return true;
    });
  }, [allData, mode, searchText, searchField, statusFilters]);

  // Pagination for Search Results
  const currentSearchPageData = useMemo(() => {
     const start = (currentPage - 1) * PAGE_SIZE;
     return searchResults.slice(start, start + PAGE_SIZE);
  }, [searchResults, currentPage]);

  const searchPageCount = Math.ceil(searchResults.length / PAGE_SIZE);

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Trigger Deep Search
    initSearch();
  };

  const handleClear = () => {
    setSearchText('');
    setStatusFilters([]);
    setMode('BROWSE');
    setCurrentPage(1);
    setCursorStack(new Map());
    setAllData([]); // Clear cache to free memory
  };

  const toggleFilter = (option: string) => {
      // Toggle Filter Logic
      const newFilters = statusFilters.includes(option)
         ? statusFilters.filter(f => f !== option)
         : [...statusFilters, option];

      setStatusFilters(newFilters);

      // If we are not searching yet, and user selects a filter, trigger Search Mode automatically
      // to ensure we search the whole DB for this status.
      if (mode === 'BROWSE' && newFilters.length > 0) {
          initSearch();
      }

      // If user clears filters in Search Mode and no text search, go back to Browse?
      // Optional: keep in search mode for stability until explicit clear.
  };

  // Close filter dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Render Helpers ---

  const renderPagination = () => {
     if (mode === 'BROWSE') {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">Page {currentPage}</span>
                 <button
                    onClick={() => setCurrentPage(p => p + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     } else {
         // Search Mode Pagination
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">
                     Page {currentPage} of {searchPageCount || 1}
                 </span>
                 <button
                    onClick={() => setCurrentPage(p => Math.min(searchPageCount, p + 1))}
                    disabled={currentPage >= searchPageCount}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     }
  };

  const activeData = mode === 'BROWSE' ? browseOrders : currentSearchPageData;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Keywords</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Search keywords in ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50"
                    >
                        {loading && mode === 'SEARCH' ? 'Scanning...' : 'Search DB'}
                    </button>

                    {(mode === 'SEARCH' || searchText || statusFilters.length > 0) && (
                        <button 
                            type="button"
                            onClick={handleClear}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Columns */}
            <colgroup>
              <col className="w-28" /> 
              <col className="w-28" />
              <col className="w-28" />
              <col className="w-24" />
              <col className="w-16" />
              <col className="w-96" />
              <col className="w-40" />
              <col className="w-24" />
              <col className="w-32" />
              <col className="w-24" />
              <col className="w-40" />
              {isAdmin && <col className="w-20" />}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center text-red-500">
                      {error}
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex flex-col items-center gap-3">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-500"></div>
                        <span>{mode === 'SEARCH' ? 'Scanning database...' : 'Loading orders...'}</span>
                    </div>
                 </td></tr>
              ) : activeData.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {mode === 'SEARCH' 
                       ? `No matches found for "${searchText}" with selected filters.` 
                       : 'No orders available.'}
                   </td>
                 </tr>
              ) : (
                activeData.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                           </div>
                        </div>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {activeData.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">
               <div className="text-xs text-slate-500 font-medium">
                 {mode === 'SEARCH' 
                    ? `Found ${searchResults.length} results` 
                    : 'Showing recent orders'}
               </div>
               {renderPagination()}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' },
  { label: 'Status', key: 'Status' } 
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- Modes ---
  // BROWSE: Server-side pagination (Efficient for initial load)
  // SEARCH: Client-side filtering of full dataset (Robust for substring/multi-field search)
  const [mode, setMode] = useState<'BROWSE' | 'SEARCH'>('BROWSE');

  // --- State ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Browse Mode State
  const [browseOrders, setBrowseOrders] = useState<OrderRecord[]>([]);
  const [cursorStack, setCursorStack] = useState<Map<number, {value: any, key: string} | null>>(new Map());
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(true);

  // Search Mode State
  const [allData, setAllData] = useState<OrderRecord[]>([]); // Cache for search
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);

  // UI State
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // --- 1. Browse Mode Logic (Server Side) ---

  const fetchBrowsePage = async (page: number, cursor: {value: any, key: string} | null) => {
    setLoading(true);
    setError(null);
    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // Default Browse: Sort by OrderDate Descending
      // Firebase sorts Ascending, so we use limitToLast
      const baseQuery = query(dbRef, orderByChild('OrderDate'));

      if (cursor) {
        // Get previous page relative to cursor
        q = query(baseQuery, endAt(cursor.value, cursor.key), limitToLast(PAGE_SIZE + 1));
      } else {
        // Get first page (latest dates)
        q = query(baseQuery, limitToLast(PAGE_SIZE));
      }

      const snapshot = await get(q);

      if (snapshot.exists()) {
        const raw: OrderRecord[] = [];
        snapshot.forEach(c => {
          raw.push({ ...c.val(), Code: c.key as string });
        });

        // Handle Overlap
        if (cursor) {
           const last = raw[raw.length - 1];
           if (last && last.Code === cursor.key) raw.pop();
        }

        // Determine Next Cursor (Oldest item in this batch, since it's limitToLast)
        if (raw.length > 0) {
            const boundary = raw[0];
            setCursorStack(prev => {
                const map = new Map(prev);
                map.set(page + 1, { value: boundary.OrderDate, key: boundary.Code });
                return map;
            });
            setHasNextPage(true);
        } else {
            setHasNextPage(false);
        }

        // Reverse to show Newest First
        setBrowseOrders(raw.reverse());
        if (raw.length === 0) setHasNextPage(false);

      } else {
        setBrowseOrders([]);
        setHasNextPage(false);
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === 'BROWSE') {
        const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
        fetchBrowsePage(currentPage, cursor);
    }
  }, [mode, currentPage]); // Remove cursorStack dependency to avoid loops

  // --- 2. Search Mode Logic (Client Side "Deep Search") ---

  const initSearch = async () => {
    setLoading(true);
    setError(null);
    try {
        // Fetch ALL data for robust filtering. 
        // Note: For very large datasets (>20k rows), consider cloud functions. 
        // For <10k rows, this is fast and provides the best UX for "contains" search.
        const dbRef = ref(db, 'order_management/master_recon_file');
        // We order by Date just to have a deterministic initial sort
        const snapshot = await get(query(dbRef, orderByChild('OrderDate'))); 

        if (snapshot.exists()) {
            const fullList: OrderRecord[] = [];
            snapshot.forEach(c => {
              fullList.push({ ...c.val(), Code: c.key as string });
            });
            // Default sort: Newest first
            fullList.reverse();
            setAllData(fullList);
            setMode('SEARCH');
            setCurrentPage(1); // Reset to page 1 of search results
        } else {
            setAllData([]);
            setMode('SEARCH');
        }
    } catch (err: any) {
        console.error(err);
        setError("Failed to search database. Please try again.");
    } finally {
        setLoading(false);
    }
  };

  // Derived State for Search Results
  const searchResults = useMemo(() => {
    if (mode !== 'SEARCH') return [];

    return allData.filter(order => {
        // 1. Text Search
        if (searchText.trim()) {
            const val = order[searchField];
            if (!val) return false;

            // Substring Match (Case Insensitive)
            if (!String(val).toLowerCase().includes(searchText.toLowerCase())) {
                return false;
            }
        }

        // 2. Status Filter
        if (statusFilters.length > 0) {
            const s = (order.Status || '').toLowerCase();
            const matches = statusFilters.some(filter => {
                if (filter === 'Shipped') return s.includes('shipped');
                if (filter === 'Canceled') return s.includes('canceled');
                if (filter === 'Duplicate') return s.includes('duplicate');
                if (filter === 'PA') return s.includes('pa');
                if (filter === 'Not shipped') return !s.includes('shipped');
                return false;
            });
            if (!matches) return false;
        }

        return true;
    });
  }, [allData, mode, searchText, searchField, statusFilters]);

  // Pagination for Search Results
  const currentSearchPageData = useMemo(() => {
     const start = (currentPage - 1) * PAGE_SIZE;
     return searchResults.slice(start, start + PAGE_SIZE);
  }, [searchResults, currentPage]);

  const searchPageCount = Math.ceil(searchResults.length / PAGE_SIZE);

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Trigger Deep Search
    initSearch();
  };

  const handleClear = () => {
    setSearchText('');
    setStatusFilters([]);
    setMode('BROWSE');
    setCurrentPage(1);
    setCursorStack(new Map());
    setAllData([]); // Clear cache to free memory
  };

  const toggleFilter = (option: string) => {
      // Toggle Filter Logic
      const newFilters = statusFilters.includes(option)
         ? statusFilters.filter(f => f !== option)
         : [...statusFilters, option];

      setStatusFilters(newFilters);

      // If we are not searching yet, and user selects a filter, trigger Search Mode automatically
      // to ensure we search the whole DB for this status.
      if (mode === 'BROWSE' && newFilters.length > 0) {
          initSearch();
      }

      // If user clears filters in Search Mode and no text search, go back to Browse?
      // Optional: keep in search mode for stability until explicit clear.
  };

  // Close filter dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Render Helpers ---

  const renderPagination = () => {
     if (mode === 'BROWSE') {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">Page {currentPage}</span>
                 <button
                    onClick={() => setCurrentPage(p => p + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     } else {
         // Search Mode Pagination
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">
                     Page {currentPage} of {searchPageCount || 1}
                 </span>
                 <button
                    onClick={() => setCurrentPage(p => Math.min(searchPageCount, p + 1))}
                    disabled={currentPage >= searchPageCount}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     }
  };

  const activeData = mode === 'BROWSE' ? browseOrders : currentSearchPageData;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Keywords</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Search keywords in ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50"
                    >
                        {loading && mode === 'SEARCH' ? 'Scanning...' : 'Search DB'}
                    </button>

                    {(mode === 'SEARCH' || searchText || statusFilters.length > 0) && (
                        <button 
                            type="button"
                            onClick={handleClear}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Columns */}
            <colgroup>
              <col className="w-28" /> 
              <col className="w-28" />
              <col className="w-28" />
              <col className="w-24" />
              <col className="w-16" />
              <col className="w-96" />
              <col className="w-40" />
              <col className="w-24" />
              <col className="w-32" />
              <col className="w-24" />
              <col className="w-40" />
              {isAdmin && <col className="w-20" />}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center text-red-500">
                      {error}
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex flex-col items-center gap-3">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-500"></div>
                        <span>{mode === 'SEARCH' ? 'Scanning database...' : 'Loading orders...'}</span>
                    </div>
                 </td></tr>
              ) : activeData.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {mode === 'SEARCH' 
                       ? `No matches found for "${searchText}" with selected filters.` 
                       : 'No orders available.'}
                   </td>
                 </tr>
              ) : (
                activeData.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                           </div>
                        </div>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {activeData.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">
               <div className="text-xs text-slate-500 font-medium">
                 {mode === 'SEARCH' 
                    ? `Found ${searchResults.length} results` 
                    : 'Showing recent orders'}
               </div>
               {renderPagination()}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' },
  { label: 'Status', key: 'Status' } 
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- Modes ---
  // BROWSE: Server-side pagination (Efficient for initial load)
  // SEARCH: Client-side filtering of full dataset (Robust for substring/multi-field search)
  const [mode, setMode] = useState<'BROWSE' | 'SEARCH'>('BROWSE');

  // --- State ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Browse Mode State
  const [browseOrders, setBrowseOrders] = useState<OrderRecord[]>([]);
  const [cursorStack, setCursorStack] = useState<Map<number, {value: any, key: string} | null>>(new Map());
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(true);

  // Search Mode State
  const [allData, setAllData] = useState<OrderRecord[]>([]); // Cache for search
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);

  // UI State
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // --- 1. Browse Mode Logic (Server Side) ---

  const fetchBrowsePage = async (page: number, cursor: {value: any, key: string} | null) => {
    // Prevent fetching if we've switched modes while waiting
    if (mode === 'SEARCH') return;

    setLoading(true);
    setError(null);
    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // Default Browse: Sort by OrderDate Descending
      const baseQuery = query(dbRef, orderByChild('OrderDate'));

      if (cursor) {
        q = query(baseQuery, endAt(cursor.value, cursor.key), limitToLast(PAGE_SIZE + 1));
      } else {
        q = query(baseQuery, limitToLast(PAGE_SIZE));
      }

      const snapshot = await get(q);

      // Double check mode after await
      if (mode === 'SEARCH') {
          setLoading(false);
          return;
      }

      if (snapshot.exists()) {
        const raw: OrderRecord[] = [];
        snapshot.forEach(c => {
          raw.push({ ...c.val(), Code: c.key as string });
        });

        if (cursor) {
           const last = raw[raw.length - 1];
           if (last && last.Code === cursor.key) raw.pop();
        }

        if (raw.length > 0) {
            const boundary = raw[0];
            setCursorStack(prev => {
                const map = new Map(prev);
                map.set(page + 1, { value: boundary.OrderDate, key: boundary.Code });
                return map;
            });
            setHasNextPage(true);
        } else {
            setHasNextPage(false);
        }

        setBrowseOrders(raw.reverse());
        if (raw.length === 0) setHasNextPage(false);

      } else {
        setBrowseOrders([]);
        setHasNextPage(false);
      }
    } catch (err: any) {
      console.error(err);
      if (mode === 'BROWSE') setError(err.message || 'Failed to load data');
    } finally {
      if (mode === 'BROWSE') setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === 'BROWSE') {
        const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
        fetchBrowsePage(currentPage, cursor);
    }
  }, [mode, currentPage]);

  // --- 2. Search Mode Logic (Client Side "Deep Search") ---

  const initSearch = async () => {
    // Switch to SEARCH immediately so UI shows "Scanning..."
    setMode('SEARCH');
    setLoading(true);
    setError(null);

    try {
        const dbRef = ref(db, 'order_management/master_recon_file');
        // Optimization: Get raw data without server sorting to avoid index requirements/delays
        const snapshot = await get(dbRef); 

        if (snapshot.exists()) {
            const val = snapshot.val();
            const fullList: OrderRecord[] = [];

            // Convert Object to Array
            Object.entries(val).forEach(([key, value]: [string, any]) => {
                fullList.push({ ...value, Code: key });
            });

            // Client-side Sort (Newest First)
            fullList.sort((a, b) => {
                const da = a.OrderDate ? new Date(a.OrderDate).getTime() : 0;
                const db = b.OrderDate ? new Date(b.OrderDate).getTime() : 0;
                return db - da;
            });

            setAllData(fullList);
            setCurrentPage(1);
        } else {
            setAllData([]);
        }
    } catch (err: any) {
        console.error(err);
        setError("Failed to download database for searching. Check internet connection.");
    } finally {
        setLoading(false);
    }
  };

  // Derived State for Search Results
  const searchResults = useMemo(() => {
    if (mode !== 'SEARCH') return [];

    return allData.filter(order => {
        // 1. Text Search
        if (searchText.trim()) {
            const val = order[searchField];
            if (!val) return false;
            if (!String(val).toLowerCase().includes(searchText.toLowerCase())) {
                return false;
            }
        }

        // 2. Status Filter
        if (statusFilters.length > 0) {
            const s = (order.Status || '').toLowerCase();
            const matches = statusFilters.some(filter => {
                const f = filter.toLowerCase();
                // Check if status field includes the filter text (e.g. "shipped" in "Order Shipped")
                return s.includes(f);
            });
            if (!matches) return false;
        }

        return true;
    });
  }, [allData, mode, searchText, searchField, statusFilters]);

  const currentSearchPageData = useMemo(() => {
     const start = (currentPage - 1) * PAGE_SIZE;
     return searchResults.slice(start, start + PAGE_SIZE);
  }, [searchResults, currentPage]);

  const searchPageCount = Math.ceil(searchResults.length / PAGE_SIZE);

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'BROWSE') {
        initSearch();
    }
  };

  const handleClear = () => {
    setSearchText('');
    setStatusFilters([]);
    setMode('BROWSE');
    setCurrentPage(1);
    setCursorStack(new Map());
    setAllData([]);
    // Browse mode useEffect will trigger data re-fetch
  };

  const toggleFilter = (option: string) => {
      const newFilters = statusFilters.includes(option)
         ? statusFilters.filter(f => f !== option)
         : [...statusFilters, option];

      setStatusFilters(newFilters);

      // If currently in browse mode, trigger deep search to apply filters across all data
      if (mode === 'BROWSE' && newFilters.length > 0) {
          initSearch();
      }
  };

  // Close filter dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Render Helpers ---

  const renderPagination = () => {
     if (mode === 'BROWSE') {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">Page {currentPage}</span>
                 <button
                    onClick={() => setCurrentPage(p => p + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     } else {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">
                     Page {currentPage} of {searchPageCount || 1}
                 </span>
                 <button
                    onClick={() => setCurrentPage(p => Math.min(searchPageCount, p + 1))}
                    disabled={currentPage >= searchPageCount}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     }
  };

  const activeData = mode === 'BROWSE' ? browseOrders : currentSearchPageData;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Keywords</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Search keywords in ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50"
                    >
                        {loading ? 'Processing...' : (mode === 'SEARCH' ? 'Search Again' : 'Search DB')}
                    </button>

                    {(mode === 'SEARCH' || searchText || statusFilters.length > 0) && (
                        <button 
                            type="button"
                            onClick={handleClear}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Columns */}
            <colgroup>
              <col className="w-28" /> 
              <col className="w-28" />
              <col className="w-28" />
              <col className="w-24" />
              <col className="w-16" />
              <col className="w-96" />
              <col className="w-40" />
              <col className="w-24" />
              <col className="w-32" />
              <col className="w-24" />
              <col className="w-40" />
              {isAdmin && <col className="w-20" />}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center text-red-500">
                      {error}
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex flex-col items-center gap-3">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-500"></div>
                        <span>{mode === 'SEARCH' ? 'Scanning entire database...' : 'Loading orders...'}</span>
                    </div>
                 </td></tr>
              ) : activeData.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {mode === 'SEARCH' 
                       ? `No matches found for "${searchText}" with selected filters.` 
                       : 'No orders available.'}
                   </td>
                 </tr>
              ) : (
                activeData.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                           </div>
                        </div>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {activeData.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">
               <div className="text-xs text-slate-500 font-medium">
                 {mode === 'SEARCH' 
                    ? `Found ${searchResults.length} results` 
                    : 'Showing recent orders'}
               </div>
               {renderPagination()}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' },
  { label: 'Status', key: 'Status' } 
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  // --- Modes ---
  // BROWSE: Server-side pagination (Efficient for initial load)
  // SEARCH: Client-side filtering of full dataset (Robust for substring/multi-field search)
  const [mode, setMode] = useState<'BROWSE' | 'SEARCH'>('BROWSE');

  // Use ref to track current mode for async callbacks
  const modeRef = useRef(mode);
  useEffect(() => {
    modeRef.current = mode;
  }, [mode]);

  // --- State ---
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Browse Mode State
  const [browseOrders, setBrowseOrders] = useState<OrderRecord[]>([]);
  const [cursorStack, setCursorStack] = useState<Map<number, {value: any, key: string} | null>>(new Map());
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(true);

  // Search Mode State
  const [allData, setAllData] = useState<OrderRecord[]>([]); // Cache for search
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);

  // UI State
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // --- 1. Browse Mode Logic (Server Side) ---

  const fetchBrowsePage = async (page: number, cursor: {value: any, key: string} | null) => {
    // Prevent fetching if we've switched modes while waiting
    if (modeRef.current === 'SEARCH') return;

    setLoading(true);
    setError(null);
    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;

      // Default Browse: Sort by OrderDate Descending
      const baseQuery = query(dbRef, orderByChild('OrderDate'));

      if (cursor) {
        q = query(baseQuery, endAt(cursor.value, cursor.key), limitToLast(PAGE_SIZE + 1));
      } else {
        q = query(baseQuery, limitToLast(PAGE_SIZE));
      }

      const snapshot = await get(q);

      // Double check mode after await using ref to get latest state
      if (modeRef.current === 'SEARCH') {
          setLoading(false);
          return;
      }

      if (snapshot.exists()) {
        const raw: OrderRecord[] = [];
        snapshot.forEach(c => {
          raw.push({ ...c.val(), Code: c.key as string });
        });

        if (cursor) {
           const last = raw[raw.length - 1];
           if (last && last.Code === cursor.key) raw.pop();
        }

        if (raw.length > 0) {
            const boundary = raw[0];
            setCursorStack(prev => {
                const map = new Map(prev);
                map.set(page + 1, { value: boundary.OrderDate, key: boundary.Code });
                return map;
            });
            setHasNextPage(true);
        } else {
            setHasNextPage(false);
        }

        setBrowseOrders(raw.reverse());
        if (raw.length === 0) setHasNextPage(false);

      } else {
        setBrowseOrders([]);
        setHasNextPage(false);
      }
    } catch (err: any) {
      console.error(err);
      if (modeRef.current === 'BROWSE') setError(err.message || 'Failed to load data');
    } finally {
      if (modeRef.current === 'BROWSE') setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === 'BROWSE') {
        const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
        fetchBrowsePage(currentPage, cursor);
    }
  }, [mode, currentPage]);

  // --- 2. Search Mode Logic (Client Side "Deep Search") ---

  const initSearch = async () => {
    // Switch to SEARCH immediately so UI shows "Scanning..."
    setMode('SEARCH');
    setLoading(true);
    setError(null);

    try {
        const dbRef = ref(db, 'order_management/master_recon_file');
        // Optimization: Get raw data without server sorting to avoid index requirements/delays
        const snapshot = await get(dbRef); 

        if (snapshot.exists()) {
            const val = snapshot.val();
            const fullList: OrderRecord[] = [];

            // Convert Object to Array
            Object.entries(val).forEach(([key, value]: [string, any]) => {
                fullList.push({ ...value, Code: key });
            });

            // Client-side Sort (Newest First)
            fullList.sort((a, b) => {
                const da = a.OrderDate ? new Date(a.OrderDate).getTime() : 0;
                const db = b.OrderDate ? new Date(b.OrderDate).getTime() : 0;
                return db - da;
            });

            setAllData(fullList);
            setCurrentPage(1);
        } else {
            setAllData([]);
        }
    } catch (err: any) {
        console.error(err);
        setError("Failed to download database for searching. Check internet connection.");
    } finally {
        setLoading(false);
    }
  };

  // Derived State for Search Results
  const searchResults = useMemo(() => {
    if (mode !== 'SEARCH') return [];

    return allData.filter(order => {
        // 1. Text Search
        if (searchText.trim()) {
            const val = order[searchField];
            if (!val) return false;
            if (!String(val).toLowerCase().includes(searchText.toLowerCase())) {
                return false;
            }
        }

        // 2. Status Filter
        if (statusFilters.length > 0) {
            const s = (order.Status || '').toLowerCase();
            const matches = statusFilters.some(filter => {
                const f = filter.toLowerCase();
                // Check if status field includes the filter text (e.g. "shipped" in "Order Shipped")
                return s.includes(f);
            });
            if (!matches) return false;
        }

        return true;
    });
  }, [allData, mode, searchText, searchField, statusFilters]);

  const currentSearchPageData = useMemo(() => {
     const start = (currentPage - 1) * PAGE_SIZE;
     return searchResults.slice(start, start + PAGE_SIZE);
  }, [searchResults, currentPage]);

  const searchPageCount = Math.ceil(searchResults.length / PAGE_SIZE);

  // --- Handlers ---

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'BROWSE') {
        initSearch();
    }
  };

  const handleClear = () => {
    setSearchText('');
    setStatusFilters([]);
    setMode('BROWSE');
    setCurrentPage(1);
    setCursorStack(new Map());
    setAllData([]);
    // Browse mode useEffect will trigger data re-fetch
  };

  const toggleFilter = (option: string) => {
      const newFilters = statusFilters.includes(option)
         ? statusFilters.filter(f => f !== option)
         : [...statusFilters, option];

      setStatusFilters(newFilters);

      // If currently in browse mode, trigger deep search to apply filters across all data
      if (mode === 'BROWSE' && newFilters.length > 0) {
          initSearch();
      }
  };

  // Close filter dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Render Helpers ---

  const renderPagination = () => {
     if (mode === 'BROWSE') {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1 || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">Page {currentPage}</span>
                 <button
                    onClick={() => setCurrentPage(p => p + 1)}
                    disabled={!hasNextPage || loading}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     } else {
         return (
             <div className="flex items-center gap-2">
                 <button
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                    disabled={currentPage === 1}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Previous
                 </button>
                 <span className="text-sm font-medium text-slate-600 px-2">
                     Page {currentPage} of {searchPageCount || 1}
                 </span>
                 <button
                    onClick={() => setCurrentPage(p => Math.min(searchPageCount, p + 1))}
                    disabled={currentPage >= searchPageCount}
                    className="px-3 py-1.5 bg-white border border-slate-200 rounded-md text-sm font-medium hover:bg-slate-50 disabled:opacity-50"
                 >
                    Next
                 </button>
             </div>
         );
     }
  };

  const activeData = mode === 'BROWSE' ? browseOrders : currentSearchPageData;

  return (
    <div className="flex flex-col gap-6 h-full">

      {/* 1. Control Panel */}
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">

            {/* Left: Search Controls */}
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
                    <select
                        value={searchField}
                        onChange={(e) => setSearchField(e.target.value)}
                        className="block w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                    >
                        {SEARCH_FIELDS.map(f => (
                            <option key={f.key} value={f.key}>{f.label}</option>
                        ))}
                    </select>
                </div>

                <div className="w-full md:flex-1 relative">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Keywords</label>
                    <div className="relative">
                        <input 
                            type="text" 
                            value={searchText}
                            onChange={(e) => setSearchText(e.target.value)}
                            placeholder={`Search keywords in ${SEARCH_FIELDS.find(f => f.key === searchField)?.label}...`}
                            className="block w-full pl-10 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                        />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                             <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                             </svg>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2 mb-0.5 items-end">
                    <button 
                        type="submit"
                        disabled={loading}
                        className="px-5 py-2 h-[42px] bg-brand-600 hover:bg-brand-700 text-white rounded-lg text-sm font-medium shadow-md transition-transform active:scale-95 disabled:opacity-50"
                    >
                        {loading ? 'Processing...' : (mode === 'SEARCH' ? 'Search Again' : 'Search DB')}
                    </button>

                    {(mode === 'SEARCH' || searchText || statusFilters.length > 0) && (
                        <button 
                            type="button"
                            onClick={handleClear}
                            className="px-4 py-2 h-[42px] bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-medium transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Right: Filters */}
            <div className="flex items-end justify-between xl:justify-end w-full xl:w-auto gap-4 border-t xl:border-t-0 border-slate-100 pt-4 xl:pt-0">
                <div className="relative" ref={filterRef}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                  <button
                    type="button"
                    onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className={`flex items-center justify-between w-full md:w-48 px-3 py-2 border rounded-lg text-sm font-medium transition-colors ${
                      statusFilters.length > 0 
                        ? 'bg-brand-50 border-brand-200 text-brand-700' 
                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                  >
                    <span className="truncate">
                      {statusFilters.length === 0 
                        ? 'Filter Status' 
                        : `${statusFilters.length} Active`}
                    </span>
                    <svg className={`w-4 h-4 ml-2 transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>

                  {isFilterOpen && (
                    <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fade-in-down">
                      <div className="p-2 space-y-1">
                        {STATUS_FILTER_OPTIONS.map(option => (
                          <label key={option} className="flex items-center px-3 py-2 hover:bg-slate-50 rounded-md cursor-pointer group">
                            <input
                              type="checkbox"
                              checked={statusFilters.includes(option)}
                              onChange={() => toggleFilter(option)}
                              className="w-4 h-4 text-brand-600 border-slate-300 rounded focus:ring-brand-500 transition-colors"
                            />
                            <span className="ml-3 text-sm text-slate-700 group-hover:text-slate-900">{option}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
            </div>
        </form>
      </div>

      {/* 2. Data Table */}
      <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden flex flex-col flex-1 min-h-0">
        <div className="flex-1 overflow-auto relative scrollbar-thin">
          <table className="min-w-full table-fixed divide-y divide-slate-100">
            {/* Columns */}
            <colgroup>
              <col className="w-28" /> 
              <col className="w-28" />
              <col className="w-28" />
              <col className="w-24" />
              <col className="w-16" />
              <col className="w-96" />
              <col className="w-40" />
              <col className="w-24" />
              <col className="w-32" />
              <col className="w-24" />
              <col className="w-40" />
              {isAdmin && <col className="w-20" />}
            </colgroup>

            <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
              <tr>
                {['Order #', 'Sales Doc', 'Date', 'Batch', 'Year', 'Material', 'Club', 'Type', 'Status', 'CDD', 'Tracking'].map(h => (
                    <th key={h} className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider truncate border-b border-slate-200">
                        {h}
                    </th>
                ))}
                {isAdmin && <th className="px-3 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider border-b border-slate-200">Action</th>}
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-slate-50">
              {error ? (
                 <tr>
                    <td colSpan={isAdmin ? 12 : 11} className="px-6 py-12 text-center text-red-500">
                      {error}
                    </td>
                 </tr>
              ) : loading ? (
                 <tr><td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                    <div className="flex flex-col items-center gap-3">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-500"></div>
                        <span>{mode === 'SEARCH' ? 'Scanning entire database...' : 'Loading orders...'}</span>
                    </div>
                 </td></tr>
              ) : activeData.length === 0 ? (
                 <tr>
                   <td colSpan={isAdmin ? 12 : 11} className="text-center py-20 text-slate-400">
                     {mode === 'SEARCH' 
                       ? `No matches found for "${searchText}" with selected filters.` 
                       : 'No orders available.'}
                   </td>
                 </tr>
              ) : (
                activeData.map((order) => {
                  const status = (order.Status || '').toLowerCase();
                  let statusColor = 'bg-slate-100 text-slate-600 border border-slate-200';
                  if (status.includes('shipped')) statusColor = 'bg-emerald-50 text-emerald-700 border border-emerald-200';
                  else if (status.includes('canceled')) statusColor = 'bg-rose-50 text-rose-700 border border-rose-200';
                  else if (status.includes('duplicate')) statusColor = 'bg-orange-50 text-orange-700 border border-orange-200';
                  else if (status.includes('pa')) statusColor = 'bg-indigo-50 text-indigo-700 border border-indigo-200';

                  return (
                    <tr key={order.Code} className="hover:bg-slate-50 transition-colors duration-150 group text-sm">
                      <td className="px-3 py-3 text-slate-900 font-medium truncate" title={String(order.OrderNumber)}>
                        {order.OrderNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={String(order.SalesDocument)}>
                        {order.SalesDocument}
                      </td>
                      <td className="px-3 py-3 text-slate-600 whitespace-nowrap truncate">
                        {order.OrderDate}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.BatchNumber}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.Year}
                      </td>
                      <td className="px-3 py-3">
                        <div className="relative group cursor-help">
                           <span className="truncate block w-full text-slate-700 font-medium">
                             {order["Material Number"]}
                           </span>
                           <div className="absolute left-0 bottom-full mb-2 hidden group-hover:block z-50 w-64 p-2 bg-slate-800 text-white text-xs rounded shadow-lg pointer-events-none">
                              {order["Material Number"]}
                           </div>
                        </div>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate" title={order.ClubName}>
                        {order.ClubName}
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.OrderType}
                      </td>
                      <td className="px-3 py-3">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-4 font-semibold rounded-full truncate max-w-full justify-center ${statusColor}`}>
                          {order.Status}
                        </span>
                      </td>
                      <td className="px-3 py-3 text-slate-600 truncate">
                        {order.CDD}
                      </td>
                      <td className="px-3 py-3 text-slate-500 font-mono text-xs truncate" title={order.UPSTrackingNumber}>
                        {order.UPSTrackingNumber}
                      </td>

                      {isAdmin && (
                        <td className="px-3 py-3 text-center">
                          <button 
                            onClick={() => onEdit(order.Code)}
                            className="text-brand-600 hover:text-brand-800 font-medium hover:underline focus:outline-none text-xs"
                          >
                            Edit
                          </button>
                        </td>
                      )}
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>

        {/* 3. Pagination Controls */}
        {activeData.length > 0 && (
            <div className="p-3 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">
               <div className="text-xs text-slate-500 font-medium">
                 {mode === 'SEARCH' 
                    ? `Found ${searchResults.length} results` 
                    : 'Showing recent orders'}
               </div>
               {renderPagination()}
            </div>
        )}
      </div>
    </div>
  );
};

