                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className={`px-2.5 py-0.5 inline-flex text-xs leading-5 font-bold rounded-full border ${
                          isAdmin 
                            ? 'bg-purple-50 text-purple-700 border-purple-200' 
