                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Qty</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Order Date</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Assigned To</th>
                   <th className="px-6 py-3 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-slate-50">
                {filteredFiles.map(file => (
                  <tr key={file.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                       <div className="flex items-center gap-3">
                         <div className="p-2 bg-green-50 rounded text-green-600">
                           <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" clipRule="evenodd" /></svg>
                         </div>
                         <div>
                           <div className="text-sm font-medium text-slate-900 truncate max-w-[200px]" title={file.name}>{file.name}</div>
                           <div className="text-xs text-slate-500">{file.category.replace('_', ' ')}</div>
                         </div>
                       </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 font-semibold">{file.totalOrders}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{file.totalQty}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{file.orderDate}</td>
                    <td className="px-6 py-4 whitespace-nowrap">
                       <select 
                         value={file.status}
                         onChange={(e) => handleStatusChange(file.id, e.target.value as ClubFileStatus)}
                         className="text-xs border-none bg-transparent focus:ring-0 cursor-pointer font-medium text-slate-700"
                       >
                         {CLUB_FILE_STATUSES.map(s => (
                           <option key={s} value={s}>{s}</option>
                         ))}
                       </select>
                       <div className="mt-1">
                         <StatusBadge status={file.status} />
                       </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                       <input 
                         type="text" 
                         placeholder="Unassigned" 
                         value={file.assignee}
                         onChange={(e) => handleAssigneeChange(file.id, e.target.value)}
                         className="text-sm border-b border-transparent hover:border-slate-300 focus:border-brand-500 focus:outline-none bg-transparent w-32 px-1"
                       />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium flex justify-end gap-2">
                       <button 
                         onClick={() => setInspectFileId(file.id)}
                         className="text-brand-600 hover:text-brand-900 bg-brand-50 hover:bg-brand-100 p-2 rounded"
                       >
                          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                       </button>
                       <button 
                         onClick={() => handleDeleteFile(file.id)}
                         className="text-red-600 hover:text-red-900 bg-red-50 hover:bg-red-100 p-2 rounded"
                       >
                          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* FILE INSPECTION MODAL */}
      {inspectFileId && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[80vh] flex flex-col">
              <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
                 <h3 className="text-xl font-bold text-slate-800">
                   File Details: {files.find(f => f.id === inspectFileId)?.name}
                 </h3>
                 <button onClick={() => setInspectFileId(null)} className="text-slate-400 hover:text-slate-600">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                 </button>
              </div>
              <div className="flex-1 overflow-auto p-0">
                 <table className="min-w-full divide-y divide-slate-100">
                    <thead className="bg-slate-50 sticky top-0">
                       <tr>
                         <th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Row #</th>
                         <th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Order ID</th>
                         <th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Club</th>
                         <th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Material</th>
                         <th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Qty</th>
                       </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-slate-50">
                       {files.find(f => f.id === inspectFileId)?.rows.map((row, idx) => (
                         <tr key={idx} className="hover:bg-slate-50">
                            <td className="px-4 py-2 text-xs text-slate-400">{idx + 1}</td>
                            <td className="px-4 py-2 text-sm text-slate-800 font-medium">{row.orderId}</td>
                            <td className="px-4 py-2 text-sm text-slate-600">{row.clubName}</td>
                            <td className="px-4 py-2 text-sm text-slate-600 truncate max-w-[200px]">{row.material}</td>
                            <td className="px-4 py-2 text-sm text-slate-600">{row.qty}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
              </div>
              <div className="px-6 py-4 border-t border-slate-100 bg-slate-50 flex justify-end">
                 <button onClick={() => setInspectFileId(null)} className="px-4 py-2 bg-white border border-slate-300 rounded text-sm font-medium text-slate-700 hover:bg-slate-50">Close</button>
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

