import React, { useState, useMemo, useRef, useCallback } from 'react';
import { CLUB_FILE_STATUSES, ClubFileStatus, ClubCategory, ProcessedFile, ClubOrderRow } from '../types';

// Declare XLSX globally as it is loaded via script tag in index.html
declare const XLSX: any;

// --- Helper Functions ---

const generateId = () => Math.random().toString(36).substr(2, 9);

const detectCategory = (filename: string): ClubCategory => {
  const lower = filename.toLowerCase();

  // Multi-sport checks (Baseball, Hockey, Volleyball, Basketball, Lacrosse, MTO)
  // Check case-insensitive
  const multiSportKeywords = ['baseball', 'hockey', 'volleyball', 'basketball', 'lacrosse', 'mto'];
  if (multiSportKeywords.some(keyword => lower.includes(keyword))) {
    return 'MULTI_SPORT';
  }

  if (lower.includes('multiple clubs')) return 'MULTIPLE_CLUBS';
  if (lower.includes('rush rs') && !lower.includes('rsa')) return 'RUSH_RS'; // differentiate RS vs RSA
  if (lower.includes('rush rsa')) return 'RUSH_RSA';
  if (lower.includes('rush miami')) return 'RUSH_MIAMI';
  if (lower.includes('replacement') || lower.includes('replacements')) return 'REPLACEMENT';
  return 'OTHER';
};

const normalizeHeader = (header: string): string => {
  return header.toString().trim().toLowerCase().replace(/[\s#]/g, '');
};

const parseExcelDate = (value: any): string => {
  if (!value) return '';
  // If it's a number (Excel serial date)
  if (typeof value === 'number') {
    // Excel base date is Dec 30 1899 approx, specific logic for JS:
    const date = new Date(Math.round((value - 25569) * 86400 * 1000));
    return date.toISOString().split('T')[0];
  }
  // Try to parse string
  const d = new Date(value);
  if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];
  return String(value);
};

// --- Components ---

const StatusBadge: React.FC<{ status: ClubFileStatus }> = ({ status }) => {
  const colors: Record<ClubFileStatus, string> = {
    'File preparing': 'bg-slate-100 text-slate-700 border-slate-200',
    'Packing list checking': 'bg-blue-50 text-blue-700 border-blue-200',
    'Correction': 'bg-orange-50 text-orange-700 border-orange-200',
    'Share': 'bg-emerald-50 text-emerald-700 border-emerald-200',
  };
  return (
    <span className={`px-2.5 py-1 text-xs font-semibold rounded-full border ${colors[status]}`}>
      {status}
    </span>
  );
};

const KpiCard: React.FC<{ title: string; value: number | string; icon: React.ReactNode; colorClass: string; subtext?: string; onClick?: () => void }> = ({ 
  title, value, icon, colorClass, subtext, onClick 
}) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-xl p-5 border border-slate-100 shadow-soft relative overflow-hidden group hover:shadow-card transition-all ${onClick ? 'cursor-pointer' : ''}`}
  >
    <div className={`absolute top-0 right-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity ${colorClass}`}>
      {React.cloneElement(icon as React.ReactElement<any>, { className: "w-16 h-16" })}
    </div>
    <div className="relative z-10">
      <div className={`h-10 w-10 rounded-lg flex items-center justify-center mb-3 ${colorClass} bg-opacity-10 text-current`}>
        {icon}
      </div>
      <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
      <div className="flex items-baseline gap-2">
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
        {subtext && <span className="text-xs text-slate-400 font-medium">{subtext}</span>}
      </div>
    </div>
  </div>
);

// --- Main Page Component ---

export const ClubOrder: React.FC = () => {
  const [batchNumber, setBatchNumber] = useState('');
  const [isBatchLocked, setIsBatchLocked] = useState(false);
  const [files, setFiles] = useState<ProcessedFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // UI State
  const [showDuplicates, setShowDuplicates] = useState(false);
  const [inspectFileId, setInspectFileId] = useState<string | null>(null);
  const [searchText, setSearchText] = useState('');

  // 1. File Upload Handler
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    // Safety check for xlsx library
    if (typeof XLSX === 'undefined') {
       setError("System Error: Excel processing library not loaded. Please refresh the page.");
       return;
    }

    setIsProcessing(true);
    setError(null);
    const uploadedFiles = Array.from(e.target.files);
    const newProcessedFiles: ProcessedFile[] = [];

    try {
      for (const file of uploadedFiles) {
        // Skip files with 'combine' in the name (case insensitive)
        if (file.name.toLowerCase().includes('combine')) {
            continue;
        }

        // Read file using FileReader
        const data = await file.arrayBuffer();
        const workbook = XLSX.read(data, { type: 'array' });

        // Pick first sheet
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        // Convert to JSON (array of arrays first to find headers, or straight to objects)
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet);

        const normalizedRows: ClubOrderRow[] = [];

        rawJson.forEach((row: any) => {
          // Normalize keys loosely
          let orderId = '';
          let salesDoc = '';
          let orderDate = '';
          let qty = 0;
          let sku = '';
          let material = '';
          let productName = '';
          let clubName = '';

          Object.keys(row).forEach(key => {
            const normKey = normalizeHeader(key);
            const val = row[key];

            if (normKey.includes('orderid') || normKey === 'order') orderId = String(val).trim();
            else if (normKey.includes('salesdoc')) salesDoc = String(val).trim();
            else if (normKey.includes('orderdate') || normKey === 'date') orderDate = parseExcelDate(val);
            else if (normKey.includes('qty') || normKey.includes('quantity')) qty = Number(val) || 0;
            else if (normKey.includes('sku')) sku = String(val);
            else if (normKey.includes('material')) material = String(val);
            else if (normKey.includes('productname') || normKey.includes('description')) productName = String(val);
            else if (normKey.includes('clubname') || normKey.includes('club')) clubName = String(val);
          });

          if (orderId) {
            normalizedRows.push({
              orderId, salesDoc, orderDate, qty, sku, material, productName, clubName, raw: row
            });
          }
        });

        // Compute File Metrics
        const uniqueOrders = new Set(normalizedRows.map(r => r.orderId));
        const totalQty = normalizedRows.reduce((sum, r) => sum + r.qty, 0);

        // Determine most frequent date
        const dateCounts: Record<string, number> = {};
        normalizedRows.forEach(r => {
          if(r.orderDate) dateCounts[r.orderDate] = (dateCounts[r.orderDate] || 0) + 1;
        });
        const bestDate = Object.keys(dateCounts).sort((a,b) => dateCounts[b] - dateCounts[a])[0] || '';

        newProcessedFiles.push({
          id: generateId(),
          name: file.name,
          category: detectCategory(file.name),
          rows: normalizedRows,
          totalOrders: uniqueOrders.size,
          totalQty,
          orderDate: bestDate,
          status: 'File preparing',
          assignee: '',
          uploadTimestamp: Date.now()
        });
      }

      setFiles(prev => [...prev, ...newProcessedFiles]);
    } catch (err: any) {
      console.error(err);
      setError("Error parsing files. Please ensure they are valid Excel files.");
    } finally {
      setIsProcessing(false);
      // Reset input
      e.target.value = ''; 
    }
  };

  // 2. Metrics Calculation (Memoized for Performance)
  const metrics = useMemo(() => {
    const allRows = files.flatMap(f => f.rows);

    // --- Global Unique Orders ---
    const globalUniqueOrders = new Set(allRows.map(r => r.orderId)).size;

    // --- Category Calculations ---
    const getCategoryUniqueCount = (cats: ClubCategory[]) => {
      const relevantRows = files
        .filter(f => cats.includes(f.category))
        .flatMap(f => f.rows);
      return new Set(relevantRows.map(r => r.orderId)).size;
    };

    const replacementTotal = getCategoryUniqueCount(['REPLACEMENT']);
    // Rush Totals - Aggregated, no longer individual
    const rushAggregateTotal = getCategoryUniqueCount(['RUSH_RS', 'RUSH_RSA', 'RUSH_MIAMI']);

    const multipleTotal = getCategoryUniqueCount(['MULTIPLE_CLUBS']);
    const multiSportTotal = getCategoryUniqueCount(['MULTI_SPORT']);

    // --- Duplicate Analysis ---
    const orderIdCounts = new Map<string, { count: number, clubs: Set<string>, files: Set<string> }>();

    allRows.forEach(row => {
      const entry = orderIdCounts.get(row.orderId) || { count: 0, clubs: new Set(), files: new Set() };
      entry.count++;
      if (row.clubName) entry.clubs.add(row.clubName);
      orderIdCounts.set(row.orderId, entry);
    });

    // Also track which files contain the order ID for better reporting
    files.forEach(f => {
      f.rows.forEach(r => {
        const entry = orderIdCounts.get(r.orderId);
        if (entry) entry.files.add(f.name);
      });
    });

    const duplicateEntries: { id: string, clubs: string[], files: string[] }[] = [];
    orderIdCounts.forEach((val, key) => {
      // A duplicate is defined as appearing more than once GLOBALLY
      if (val.count > 1) {
        duplicateEntries.push({
           id: key, 
           clubs: Array.from(val.clubs),
           files: Array.from(val.files)
        });
      }
    });

    return {
      globalUniqueOrders,
      replacementTotal,
      multipleTotal,
      multiSportTotal,
      rushAggregateTotal,
      duplicateCount: duplicateEntries.length,
      duplicates: duplicateEntries
    };
  }, [files]);

  // 3. Status & Assignee Handlers
  const handleStatusChange = (fileId: string, newStatus: ClubFileStatus) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, status: newStatus } : f));
  };

  const handleAssigneeChange = (fileId: string, assignee: string) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, assignee } : f));
  };

  const handleDeleteFile = (fileId: string) => {
    if(window.confirm("Remove this file?")) {
      setFiles(prev => prev.filter(f => f.id !== fileId));
    }
  };

  // 4. Filtering
  const filteredFiles = useMemo(() => {
    if (!searchText) return files;
    const lower = searchText.toLowerCase();
    return files.filter(f => f.name.toLowerCase().includes(lower));
  }, [files, searchText]);


  return (
    <div className="space-y-8 pb-20">

      {/* HEADER & BATCH INPUT */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Club Order Management</h1>
          <p className="text-slate-500">Upload, analyze, and track club orders efficiently.</p>
        </div>

        <div className="flex items-center gap-2 bg-white p-2 rounded-lg shadow-sm border border-slate-200">
           <div className="px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-500 uppercase">Batch #</div>
           {isBatchLocked ? (
             <div className="flex items-center gap-3 pl-2 pr-2">
               <span className="text-lg font-bold text-slate-800 font-mono tracking-tight">{batchNumber}</span>
               <button 
                onClick={() => setIsBatchLocked(false)}
                className="text-xs text-brand-600 hover:underline"
               >
                 Change
               </button>
             </div>
           ) : (
             <div className="flex gap-2">
               <input 
                  type="text" 
                  value={batchNumber}
                  onChange={(e) => setBatchNumber(e.target.value)}
                  placeholder="Enter Batch No."
                  className="bg-white border border-slate-300 rounded px-2 py-1 text-slate-800 font-bold placeholder-slate-400 w-40 focus:outline-none focus:ring-2 focus:ring-brand-500"
               />
               <button 
                 disabled={!batchNumber}
                 onClick={() => setIsBatchLocked(true)}
                 className="bg-brand-600 text-white px-3 py-1 rounded text-sm font-medium hover:bg-brand-700 disabled:opacity-50"
               >
                 Set
               </button>
             </div>
           )}
        </div>
      </div>

      {/* KPI CARDS - Only show if files exist */}
      {files.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 animate-fade-in-up">
           <KpiCard 
             title="Global Orders" 
             value={metrics.globalUniqueOrders} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
             colorClass="text-indigo-600"
             subtext="Unique"
           />
           <KpiCard 
             title="Duplicates" 
             value={metrics.duplicateCount} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>}
             colorClass="text-red-600"
             subtext="Click to view"
             onClick={() => setShowDuplicates(!showDuplicates)}
           />
           <KpiCard 
             title="Rush Total" 
             value={metrics.rushAggregateTotal} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>}
             colorClass="text-amber-600"
           />
           <KpiCard 
             title="Replacement" 
             value={metrics.replacementTotal} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>}
             colorClass="text-emerald-600"
           />
           <KpiCard 
             title="Multiple Club" 
             value={metrics.multipleTotal} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>}
             colorClass="text-purple-600"
           />
           <KpiCard 
             title="Multi-sport" 
             value={metrics.multiSportTotal} 
             icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
             colorClass="text-teal-600"
           />
        </div>
      )}

      {/* DUPLICATE PANEL */}
      {showDuplicates && metrics.duplicateCount > 0 && (
         <div className="bg-white border border-red-100 rounded-xl shadow-soft overflow-hidden animate-fade-in-down">
            <div className="px-6 py-4 bg-red-50 border-b border-red-100 flex justify-between items-center">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-white rounded-lg text-red-600 shadow-sm">
                   <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                 </div>
                 <h3 className="text-lg font-bold text-red-800">Duplicate Order Report</h3>
               </div>
               <button onClick={() => setShowDuplicates(false)} className="text-red-500 hover:text-red-700">
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
               </button>
            </div>
            <div className="max-h-64 overflow-y-auto">
               <table className="min-w-full divide-y divide-red-100">
                 <thead className="bg-red-50/50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Order ID</th>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Clubs Involved</th>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Source Files</th>
                    </tr>
                 </thead>
                 <tbody className="bg-white divide-y divide-red-50">
                    {metrics.duplicates.map(dup => (
                      <tr key={dup.id}>
                        <td className="px-6 py-3 text-sm font-medium text-slate-900">{dup.id}</td>
                        <td className="px-6 py-3 text-sm text-slate-600">{dup.clubs.join(', ')}</td>
                        <td className="px-6 py-3 text-sm text-slate-500 text-xs italic">{dup.files.join(', ')}</td>
                      </tr>
                    ))}
                 </tbody>
               </table>
            </div>
         </div>
      )}

      {/* UPLOAD ZONE */}
      <div className={`border-2 border-dashed rounded-xl p-10 text-center transition-colors ${
          isBatchLocked 
            ? 'border-brand-300 bg-brand-50 hover:bg-brand-100 cursor-pointer' 
            : 'border-slate-200 bg-slate-50 opacity-60 cursor-not-allowed'
        }`}>
         <input 
           type="file" 
           multiple 
           accept=".xlsx,.xls"
           onChange={handleFileUpload}
           disabled={!isBatchLocked || isProcessing}
           className="hidden" 
           id="file-upload" 
         />
         <label htmlFor="file-upload" className={`flex flex-col items-center justify-center ${isBatchLocked ? 'cursor-pointer' : ''}`}>
           {isProcessing ? (
              <div className="flex flex-col items-center">
                 <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-600 mb-4"></div>
                 <span className="text-brand-600 font-medium">Processing files...</span>
              </div>
           ) : (
             <>
               <div className={`p-4 rounded-full mb-4 ${isBatchLocked ? 'bg-white text-brand-600 shadow-sm' : 'bg-slate-200 text-slate-400'}`}>
                 <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                 </svg>
               </div>
               <h3 className={`text-lg font-bold mb-1 ${isBatchLocked ? 'text-slate-800' : 'text-slate-400'}`}>
                 {isBatchLocked ? 'Click or Drag files to upload' : 'Enter Batch Number First'}
               </h3>
               <p className="text-sm text-slate-500">Supports .xlsx and .xls (Max 25 files at once)</p>
             </>
           )}
         </label>
      </div>

      {error && (
        <div className="p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg flex items-center">
           <svg className="w-5 h-5 mr-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
           {error}
        </div>
      )}

      {/* FILES TABLE */}
      {files.length > 0 && (
        <div className="bg-white rounded-xl shadow-card border border-slate-100 overflow-hidden">
          <div className="px-6 py-5 border-b border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
             <div>
                <h3 className="text-lg font-bold text-slate-800">Files Overview</h3>
                <p className="text-sm text-slate-500">{files.length} files loaded in this batch</p>
             </div>
             <div className="relative">
                <input 
                  type="text" 
                  placeholder="Search files..." 
                  value={searchText}
                  onChange={(e) => setSearchText(e.target.value)}
                  className="pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-brand-500 w-64"
                />
                <svg className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
             </div>
          </div>

          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-100">
              <thead className="bg-slate-50">
                <tr>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">File Name</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Orders</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Qty</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Order Date</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                   <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Assigned To</th>
                   <th className="px-6 py-3 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-slate-50">
                {filteredFiles.map(file => (
                  <tr key={file.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                       <div className="flex items-center gap-3">
                         <div className="p-2 bg-green-50 rounded text-green-600">
                           <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" clipRule="evenodd" /></svg>
                         </div>
                         <div>
                           <div className="text-sm font-medium text-slate-900 truncate max-w-[200px]" title={file.name}>{file.name}</div>
