export const ClubOrder: React.FC = () => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  const [batchNumber, setBatchNumber] = useState('');
  const [isBatchLocked, setIsBatchLocked] = useState(false);
  const [allBatchKeys, setAllBatchKeys] = useState<string[]>([]);
  const [files, setFiles] = useState<ProcessedFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // UI State
  const [showDuplicates, setShowDuplicates] = useState(false);
  const [inspectFileId, setInspectFileId] = useState<string | null>(null);
  const [searchText, setSearchText] = useState('');
  const [masterReconKeys, setMasterReconKeys] = useState<Set<string>>(new Set());
  const [verifyingDuplicates, setVerifyingDuplicates] = useState(false);

  // 1. Initial Load: Resolve Latest Batch
  useEffect(() => {
    const init = async () => {
      setVerifyingDuplicates(true);
      try {
        const collectionRef = ref(db, 'order_management/club_collection');
        const snapshot = await get(collectionRef);

        if (snapshot.exists()) {
          const keys = Object.keys(snapshot.val());
          setAllBatchKeys(keys);
          const latest = resolveLatestBatch(keys);
          if (latest) {
            setBatchNumber(latest);
            loadBatch(latest);
          }
        }
      } catch (err) {
        console.error("Init error:", err);
      } finally {
        setVerifyingDuplicates(false);
      }
    };
    init();
  }, []);

  const loadBatch = async (key: string) => {
    setIsProcessing(true);
    try {
      const batchRef = ref(db, `order_management/club_collection/${key}`);
      const snapshot = await get(batchRef);
      if (snapshot.exists()) {
        const data = snapshot.val();
        // Firebase objects to array
        const loadedFiles: ProcessedFile[] = data.files ? Object.values(data.files) : [];
        setFiles(loadedFiles);
        setIsBatchLocked(true);
      } else {
        setFiles([]);
        setIsBatchLocked(false);
      }
    } catch (err) {
      setError("Failed to load batch data.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveBatch = async () => {
    if (!isAdmin || !batchNumber || files.length === 0) return;
    setIsSaving(true);
    try {
      const batchRef = ref(db, `order_management/club_collection/${batchNumber}`);

      // Calculate global totals for metadata
      const allRows = files.flatMap(f => f.rows);
      const globalOrders = new Set(allRows.map(r => r.orderId)).size;
      const totalQty = allRows.reduce((sum, r) => sum + r.qty, 0);

      // Convert array to object for Firebase to prevent numeric indexing issues
      const filesObj: Record<string, any> = {};
      files.forEach(f => {
        // Sanitize name for key
        const safeName = f.id; // Using ID as key is safer than name
        filesObj[safeName] = f;
      });

      await set(batchRef, {
        metadata: {
          date_time: new Date().toISOString(),
          global_orders: globalOrders,
          total_qty: totalQty,
          uploaded_by: userProfile?.name || 'Unknown'
        },
        files: filesObj
      });

      if (!allBatchKeys.includes(batchNumber)) {
        setAllBatchKeys(prev => [...prev, batchNumber]);
      }
      alert("Batch saved successfully!");
    } catch (err) {
      console.error(err);
      setError("Failed to save batch to database.");
    } finally {
      setIsSaving(false);
    }
  };

  // 2. Master Recon Duplicate Check
  const verifyDuplicatesAgainstMaster = async () => {
    setVerifyingDuplicates(true);
    try {
      // In a real optimized system, we might use a cloud function or 
      // check presence of specific IDs. Here we fetch the keys of the master file.
      // Note: fetching the whole master file is expensive if it has 50k+ entries.
      // For this demo context, we assume the user can afford the read.
      const reconRef = ref(db, 'order_management/master_recon_file');
      const snapshot = await get(reconRef);
      if (snapshot.exists()) {
        const reconData = snapshot.val();
        // Since master_recon_file is keyed by Order ID/Code
        const keys = new Set(Object.keys(reconData));
        setMasterReconKeys(keys);
        setShowDuplicates(true);
      }
    } catch (err) {
      setError("Failed to verify against master database.");
    } finally {
      setVerifyingDuplicates(false);
    }
  };

  // 3. File Upload Handler
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;
    if (typeof XLSX === 'undefined') {
       setError("Excel library missing. Please refresh.");
       return;
    }

    setIsProcessing(true);
    setError(null);
    const uploadedFiles = Array.from(e.target.files);
    const newProcessedFiles: ProcessedFile[] = [];

    try {
      for (const file of uploadedFiles) {
        if (file.name.toLowerCase().includes('combine')) continue;

        const data = await file.arrayBuffer();
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet);

        const normalizedRows: ClubOrderRow[] = [];
        rawJson.forEach((row: any) => {
          let orderId = '', salesDoc = '', orderDate = '', qty = 0, sku = '', material = '', productName = '', clubName = '';
          Object.keys(row).forEach(key => {
            const normKey = normalizeHeader(key);
            const val = row[key];
            if (normKey.includes('orderid') || normKey === 'order') orderId = String(val).trim();
            else if (normKey.includes('salesdoc')) salesDoc = String(val).trim();
            else if (normKey.includes('orderdate') || normKey === 'date') orderDate = parseExcelDate(val);
            else if (normKey.includes('qty') || normKey.includes('quantity')) qty = Number(val) || 0;
            else if (normKey.includes('sku')) sku = String(val);
            else if (normKey.includes('material')) material = String(val);
            else if (normKey.includes('productname') || normKey.includes('description')) productName = String(val);
            else if (normKey.includes('clubname') || normKey.includes('club')) clubName = String(val);
          });
          if (orderId) normalizedRows.push({ orderId, salesDoc, orderDate, qty, sku, material, productName, clubName, raw: row });
        });

        const uniqueOrders = new Set(normalizedRows.map(r => r.orderId));
        const dateCounts: Record<string, number> = {};
        normalizedRows.forEach(r => { if(r.orderDate) dateCounts[r.orderDate] = (dateCounts[r.orderDate] || 0) + 1; });
        const bestDate = Object.keys(dateCounts).sort((a,b) => dateCounts[b] - dateCounts[a])[0] || '';

        newProcessedFiles.push({
          id: generateId(),
          name: file.name,
          category: detectCategory(file.name),
          rows: normalizedRows,
          totalOrders: uniqueOrders.size,
          totalQty: normalizedRows.reduce((sum, r) => sum + r.qty, 0),
          orderDate: bestDate,
          status: 'File preparing',
          assignee: '',
          uploadTimestamp: Date.now()
        });
      }
      setFiles(prev => [...prev, ...newProcessedFiles]);
    } catch (err: any) {
      setError("Error parsing files.");
    } finally {
      setIsProcessing(false);
      e.target.value = ''; 
    }
  };

  // 4. Metrics Calculation
  const metrics = useMemo(() => {
    const allRows = files.flatMap(f => f.rows);
    const globalUniqueOrders = new Set(allRows.map(r => r.orderId)).size;

    const getCount = (cats: ClubCategory[]) => {
      const rows = files.filter(f => cats.includes(f.category)).flatMap(f => f.rows);
      return new Set(rows.map(r => r.orderId)).size;
    };

    const duplicateEntries: { id: string, clubs: string[], files: string[] }[] = [];
    const orderIdMap = new Map<string, { clubs: Set<string>, files: Set<string> }>();

    allRows.forEach(row => {
      const entry = orderIdMap.get(row.orderId) || { clubs: new Set(), files: new Set() };
      if (row.clubName) entry.clubs.add(row.clubName);
      orderIdMap.set(row.orderId, entry);
    });

    files.forEach(f => f.rows.forEach(r => orderIdMap.get(r.orderId)?.files.add(f.name)));

    orderIdMap.forEach((val, key) => {
      // Logic: It's a duplicate IF it's in the master recon file
      if (masterReconKeys.has(key)) {
        duplicateEntries.push({ id: key, clubs: Array.from(val.clubs), files: Array.from(val.files) });
      }
    });

    return {
      globalUniqueOrders,
      replacementTotal: getCount(['REPLACEMENT']),
      multipleTotal: getCount(['MULTIPLE_CLUBS']),
      multiSportTotal: getCount(['MULTI_SPORT']),
      rushAggregateTotal: getCount(['RUSH_RS', 'RUSH_RSA', 'RUSH_MIAMI']),
      duplicateCount: duplicateEntries.length,
      duplicates: duplicateEntries
    };
  }, [files, masterReconKeys]);

  const handleStatusChange = (fileId: string, newStatus: ClubFileStatus) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, status: newStatus } : f));
  };

  const handleAssigneeChange = (fileId: string, assignee: string) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, assignee } : f));
  };

  return (
    <div className="space-y-8 pb-20">

      {/* HEADER */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Club Order Management</h1>
          <p className="text-slate-500">Persisted batch management with SAP reconciliation check.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
           <div className="flex items-center gap-2 bg-white p-2 rounded-lg shadow-sm border border-slate-200">
              <div className="px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-500 uppercase">Batch #</div>
              {isBatchLocked ? (
                <div className="flex items-center gap-3 pl-2 pr-2">
                  <span className="text-lg font-bold text-slate-800 font-mono tracking-tight">{batchNumber}</span>
                  <button onClick={() => setIsBatchLocked(false)} className="text-xs text-brand-600 hover:underline">Change</button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <input type="text" value={batchNumber} onChange={(e) => setBatchNumber(e.target.value)} placeholder="Batch No." className="bg-white border border-slate-300 rounded px-2 py-1 text-slate-800 font-bold w-32 focus:outline-none focus:ring-2 focus:ring-brand-500" />
                  <button disabled={!batchNumber} onClick={() => loadBatch(batchNumber)} className="bg-brand-600 text-white px-3 py-1 rounded text-sm font-medium hover:bg-brand-700 disabled:opacity-50">Set</button>
                </div>
              )}
           </div>

           {allBatchKeys.length > 0 && !isBatchLocked && (
             <select 
               className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-600 shadow-sm"
               onChange={(e) => {
                 const key = e.target.value;
                 if (key) {
                   setBatchNumber(key);
                   loadBatch(key);
                 }
               }}
               value={batchNumber}
             >
               <option value="">Load History...</option>
               {allBatchKeys.map(k => <option key={k} value={k}>{k}</option>)}
             </select>
           )}

           {isAdmin && isBatchLocked && files.length > 0 && (
             <button 
               onClick={handleSaveBatch}
               disabled={isSaving}
               className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg shadow-md transition-all active:scale-95 disabled:opacity-50"
             >
               {isSaving ? 'Saving...' : (
                 <>
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" /></svg>
                   Save Batch
                 </>
               )}
             </button>
           )}
        </div>
      </div>

      {/* KPI CARDS */}
      {files.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 animate-fade-in-up">
           <KpiCard title="Global Orders" value={metrics.globalUniqueOrders} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-indigo-600" subtext="Unique" />
           <KpiCard title="Duplicates" value={metrics.duplicateCount} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>} colorClass="text-red-600" subtext={verifyingDuplicates ? "Verifying..." : "Click to check"} onClick={verifyDuplicatesAgainstMaster} />
           <KpiCard title="Rush Total" value={metrics.rushAggregateTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>} colorClass="text-amber-600" />
           <KpiCard title="Replacement" value={metrics.replacementTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>} colorClass="text-emerald-600" />
           <KpiCard title="Multiple Club" value={metrics.multipleTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>} colorClass="text-purple-600" />
           <KpiCard title="Multi-sport" value={metrics.multiSportTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-teal-600" />
        </div>
      )}

      {/* DUPLICATE PANEL */}
      {showDuplicates && (
         <div className="bg-white border border-red-100 rounded-xl shadow-soft overflow-hidden animate-fade-in-down">
            <div className="px-6 py-4 bg-red-50 border-b border-red-100 flex justify-between items-center">
               <h3 className="text-lg font-bold text-red-800">Verified Duplicate Analysis (vs SAP Database)</h3>
               <button onClick={() => setShowDuplicates(false)} className="text-red-500 hover:text-red-700">
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
               </button>
            </div>
            <div className="max-h-64 overflow-y-auto">
               <table className="min-w-full divide-y divide-red-100">
                 <thead className="bg-red-50/50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Order ID</th>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Clubs</th>
                      <th className="px-6 py-3 text-left text-xs font-semibold text-red-800 uppercase tracking-wider">Status</th>
                    </tr>
                 </thead>
                 <tbody className="bg-white divide-y divide-red-50">
                    {metrics.duplicates.length > 0 ? metrics.duplicates.map(dup => (
                      <tr key={dup.id}>
                        <td className="px-6 py-3 text-sm font-medium text-slate-900">{dup.id}</td>
                        <td className="px-6 py-3 text-sm text-slate-600">{dup.clubs.join(', ')}</td>
                        <td className="px-6 py-3 text-xs text-red-600 font-bold uppercase">ALREADY IN RECON FILE</td>
                      </tr>
                    )) : (
                      <tr><td colSpan={3} className="px-6 py-10 text-center text-slate-500 italic">No duplicates found in current batch.</td></tr>
                    )}
                 </tbody>
               </table>
            </div>
         </div>
      )}

      {/* UPLOAD ZONE */}
      <div className={`border-2 border-dashed rounded-xl p-10 text-center transition-colors ${isBatchLocked ? 'border-brand-300 bg-brand-50 hover:bg-brand-100 cursor-pointer' : 'border-slate-200 bg-slate-50 opacity-60 cursor-not-allowed'}`}>
