                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{file.totalQty}</td>
                    <td className="px-6 py-4">
                       <select value={file.status} onChange={(e) => handleStatusChange(file.id, e.target.value as ClubFileStatus)} className="text-xs border-none bg-transparent cursor-pointer font-medium text-slate-700">
