                    <td className="px-6 py-4">
                       <input type="text" placeholder="Unassigned" value={file.assignee} onChange={(e) => handleAssigneeChange(file.id, e.target.value)} className="text-sm border-b border-transparent hover:border-slate-300 focus:border-brand-500 focus:outline-none bg-transparent w-32" />
