      {/* INSPECT MODAL */}
      {inspectFileId && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[80vh] flex flex-col">
              <div className="px-6 py-4 border-b flex justify-between items-center">
                 <h3 className="font-bold text-slate-800">Rows in {files.find(f => f.id === inspectFileId)?.name}</h3>
                 <button onClick={() => setInspectFileId(null)} className="text-slate-400">Close</button>
              </div>
              <div className="flex-1 overflow-auto">
                 <table className="min-w-full divide-y">
                    <thead className="bg-slate-50 sticky top-0">
                       <tr><th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Order ID</th><th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Club</th><th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Material</th><th className="px-4 py-2 text-left text-xs font-semibold text-slate-500">Qty</th></tr>
                    </thead>
                    <tbody className="bg-white divide-y">
                       {files.find(f => f.id === inspectFileId)?.rows.map((row, idx) => (
                         <tr key={idx}><td className="px-4 py-2 text-sm text-slate-800">{row.orderId}</td><td className="px-4 py-2 text-sm text-slate-600">{row.clubName}</td><td className="px-4 py-2 text-sm text-slate-600">{row.material}</td><td className="px-4 py-2 text-sm text-slate-600">{row.qty}</td></tr>
                       ))}
