import React, { useState, useMemo, useEffect } from 'react';
import { db } from '../services/firebase';
import { ref, get, update } from 'firebase/database';
import { CLUB_FILE_STATUSES, ClubFileStatus, ClubCategory, ProcessedFile, ClubOrderRow, UserProfile } from '../types';
import { useAuth } from '../context/AuthContext';

declare const XLSX: any;

const generateId = () => Math.random().toString(36).substr(2, 9);

const sanitizeKey = (key: string) => key.replace(/#/g, '_HASH_');
const desanitizeKey = (key: string) => key.replace(/_HASH_/g, '#');

const detectCategory = (filename: string): ClubCategory => {
  const lower = filename.toLowerCase();
  const multiSportKeywords = ['baseball', 'hockey', 'volleyball', 'basketball', 'lacrosse', 'mto', 'multi-sport', 'multisport'];
  if (multiSportKeywords.some(keyword => lower.includes(keyword))) return 'MULTI_SPORT';
  if (lower.includes('multiple clubs')) return 'MULTIPLE_CLUBS';
  if (lower.includes('rush rs') && !lower.includes('rsa')) return 'RUSH_RS';
  if (lower.includes('rush rsa')) return 'RUSH_RSA';
  if (lower.includes('rush miami')) return 'RUSH_MIAMI';
  if (lower.includes('replacement') || lower.includes('replacements')) return 'REPLACEMENT';
  return 'OTHER';
};

const normalizeHeader = (header: string): string => {
  return header.toString().trim().toLowerCase().replace(/[\s#]/g, '');
};

const parseExcelDate = (value: any): string => {
  if (!value) return '';
  if (typeof value === 'number') {
    const date = new Date(Math.round((value - 25569) * 86400 * 1000));
    return date.toISOString().split('T')[0];
  }
  const d = new Date(value);
  if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];
  return String(value);
};

const resolveLatestBatch = (keys: string[]): string | null => {
  if (keys.length === 0) return null;
  return [...keys].sort((a, b) => {
    const aParts = a.replace(/_HASH_/g, '#').split('#').map(n => parseInt(n) || 0);
    const bParts = b.replace(/_HASH_/g, '#').split('#').map(n => parseInt(n) || 0);
    if (aParts[0] !== bParts[0]) return bParts[0] - aParts[0];
    return (bParts[1] || 0) - (aParts[1] || 0);
  })[0];
};

const StatusBadge: React.FC<{ status: ClubFileStatus }> = ({ status }) => {
  const colors: Record<ClubFileStatus, string> = {
    'File preparing': 'bg-slate-100 text-slate-700 border-slate-200',
    'Packing list checking': 'bg-blue-100 text-blue-700 border-blue-200',
    'Correction': 'bg-orange-100 text-orange-700 border-orange-200',
    'Share': 'bg-emerald-100 text-emerald-700 border-emerald-200',
  };
  return (
    <span className={`px-2.5 py-1 text-[10px] font-bold rounded-full border uppercase tracking-wider ${colors[status]}`}>
      {status}
    </span>
  );
};

const KpiCard: React.FC<{ title: string; value: number | string; icon: React.ReactNode; colorClass: string; subtext?: string; onClick?: () => void }> = ({ 
  title, value, icon, colorClass, subtext, onClick 
}) => (
  <div onClick={onClick} className={`bg-white rounded-xl p-5 border border-slate-100 shadow-soft relative overflow-hidden group hover:shadow-card transition-all ${onClick ? 'cursor-pointer' : ''}`}>
    <div className={`absolute top-0 right-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity ${colorClass}`}>
      {React.cloneElement(icon as React.ReactElement<any>, { className: "w-16 h-16" })}
    </div>
    <div className="relative z-10">
      <div className={`h-10 w-10 rounded-lg flex items-center justify-center mb-3 ${colorClass} bg-opacity-10 text-current`}>
        {icon}
      </div>
      <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
      <div className="flex items-baseline gap-2">
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
        {subtext && <span className="text-xs text-slate-400 font-medium">{subtext}</span>}
      </div>
    </div>
  </div>
);

export const ClubOrder: React.FC = () => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  const [batchNumber, setBatchNumber] = useState('');
  const [isBatchLocked, setIsBatchLocked] = useState(false);
  const [allBatchKeys, setAllBatchKeys] = useState<string[]>([]);
  const [files, setFiles] = useState<ProcessedFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [showDuplicates, setShowDuplicates] = useState(false);
  const [inspectFileId, setInspectFileId] = useState<string | null>(null);
  const [searchText, setSearchText] = useState('');
  const [masterReconKeys, setMasterReconKeys] = useState<Set<string>>(new Set());
  const [verifyingDuplicates, setVerifyingDuplicates] = useState(false);
  const [availableUsers, setAvailableUsers] = useState<string[]>([]);

  // Load Initial Data: Batch Keys and User List
  useEffect(() => {
    const init = async () => {
      try {
        // Fetch Batches
        const collectionRef = ref(db, 'order_management/club_collection');
        const snapshot = await get(collectionRef);
        if (snapshot.exists()) {
          const rawKeys = Object.keys(snapshot.val());
          setAllBatchKeys(rawKeys.map(desanitizeKey));
          const latestRaw = resolveLatestBatch(rawKeys);
          if (latestRaw) {
            const latestDisplay = desanitizeKey(latestRaw);
            setBatchNumber(latestDisplay);
            loadBatch(latestDisplay);
          }
        }

        // Fetch Users for Assignment Dropdown
        const usersRef = ref(db, 'users');
        const usersSnapshot = await get(usersRef);
        if (usersSnapshot.exists()) {
          const usersData = usersSnapshot.val();
          const names = Object.values(usersData).map((u: any) => u.name).filter(Boolean);
          setAvailableUsers(names);
        }
      } catch (err) {
        console.error("Init load error:", err);
      }
    };
    init();
  }, []);

  const loadBatch = async (displayKey: string) => {
    if (!displayKey) return;
    setIsProcessing(true);
    setError(null);
    const safeKey = sanitizeKey(displayKey);
    try {
      const batchRef = ref(db, `order_management/club_collection/${safeKey}`);
      const snapshot = await get(batchRef);
      if (snapshot.exists()) {
        const data = snapshot.val();
        const loadedFiles: ProcessedFile[] = Object.entries(data).map(([fileName, details]: [string, any]) => {
          if (['date', 'global_orders', 'uploaded_by', 'metadata'].includes(fileName)) return null;
          return {
            id: generateId(),
            name: fileName.replace(/_DOT_/g, '.'),
            totalOrders: details.order || 0,
            totalQty: details.qty || 0,
            status: details.status || 'File preparing',
            assignee: details.assigned || '',
            category: detectCategory(fileName),
            rows: [], 
            uploadTimestamp: Date.now()
          };
        }).filter(f => f !== null) as ProcessedFile[];
        setFiles(loadedFiles);
      } else {
        setFiles([]);
      }
      setIsBatchLocked(true);
    } catch (err: any) {
      setError("Failed to connect to database. Check internet or permissions.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveBatch = async () => {
    if (!isAdmin || !batchNumber || files.length === 0) return;
    setIsSaving(true);
    const safeBatchKey = sanitizeKey(batchNumber);
    const updates: Record<string, any> = {};

    try {
      const allRows = files.flatMap(f => f.rows);
      const globalUniqueOrders = new Set(allRows.map(r => r.orderId)).size;

      const batchSummary: Record<string, any> = {
        date: new Date().toLocaleString(),
        global_orders: globalUniqueOrders || files.reduce((s,f) => s+f.totalOrders,0),
        uploaded_by: userProfile?.name || 'Unknown'
      };

      files.forEach(f => {
        const safeFileName = f.name.replace(/\./g, '_DOT_');
        batchSummary[safeFileName] = {
          order: f.totalOrders,
          qty: f.totalQty,
          status: f.status,
          assigned: f.assignee
        };
      });

      updates[`order_management/club_collection/${safeBatchKey}`] = batchSummary;

      allRows.forEach(row => {
        const detailKey = `${row.orderId}${row.material}`;
        updates[`order_management/master_recon_file/${detailKey}`] = {
          OrderNumber: row.orderId,
          SalesDocument: row.salesDoc,
          OrderDate: row.orderDate,
          BatchNumber: batchNumber,
          Year: new Date(row.orderDate).getFullYear() || "2025",
          "Material Number": row.material,
          ClubName: row.clubName,
          OrderType: null,
          Status: "file preparing",
          CDD: null,
          qty: row.qty,
          sku: row.sku,
          productName: row.productName
        };
      });

      await update(ref(db), updates);

      if (!allBatchKeys.includes(batchNumber)) {
        setAllBatchKeys(prev => [...prev, batchNumber]);
      }
      alert(`Batch ${batchNumber} saved successfully.`);
    } catch (err) {
      console.error(err);
      setError("Failed to save data to database.");
    } finally {
      setIsSaving(false);
    }
  };

  const verifyDuplicatesAgainstMaster = async () => {
    if (files.length === 0) return;
    setVerifyingDuplicates(true);
    try {
      const reconRef = ref(db, 'order_management/master_recon_file');
      const snapshot = await get(reconRef);
      if (snapshot.exists()) {
        const reconData = snapshot.val();
        const keys = new Set(Object.keys(reconData));
        setMasterReconKeys(keys);
        setShowDuplicates(true);
      }
    } catch (err) {
      setError("Failed to verify against master database.");
    } finally {
      setVerifyingDuplicates(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;
    setIsProcessing(true);
    setError(null);
    const uploadedFiles = Array.from(e.target.files);
    const newProcessedFiles: ProcessedFile[] = [];

    try {
      for (const file of uploadedFiles) {
        if (file.name.toLowerCase().includes('combine')) continue;
        const data = await file.arrayBuffer();
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet);

        const normalizedRows: ClubOrderRow[] = [];
        rawJson.forEach((row: any) => {
          let orderId = '', salesDoc = '', orderDate = '', qty = 0, sku = '', material = '', productName = '', clubName = '';
          Object.keys(row).forEach(key => {
            const normKey = normalizeHeader(key);
            const val = row[key];
            if (normKey.includes('orderid') || normKey === 'order') orderId = String(val).trim();
            else if (normKey.includes('salesdoc')) salesDoc = String(val).trim();
            else if (normKey.includes('orderdate') || normKey === 'date') orderDate = parseExcelDate(val);
            else if (normKey.includes('qty') || normKey.includes('quantity')) qty = Number(val) || 0;
            else if (normKey.includes('sku')) sku = String(val);
            else if (normKey.includes('material')) material = String(val);
            else if (normKey.includes('productname') || normKey.includes('description')) productName = String(val);
            else if (normKey.includes('clubname') || normKey.includes('club')) clubName = String(val);
          });
          if (orderId) normalizedRows.push({ orderId, salesDoc, orderDate, qty, sku, material, productName, clubName, raw: row });
        });

        if (normalizedRows.length === 0) continue;

        const uniqueOrdersInFile = new Set(normalizedRows.map(r => r.orderId));
        const dateCounts: Record<string, number> = {};
        normalizedRows.forEach(r => { if(r.orderDate) dateCounts[r.orderDate] = (dateCounts[r.orderDate] || 0) + 1; });
        const bestDate = Object.keys(dateCounts).sort((a,b) => dateCounts[b] - dateCounts[a])[0] || '';

        newProcessedFiles.push({
          id: generateId(),
          name: file.name,
          category: detectCategory(file.name),
          rows: normalizedRows,
          totalOrders: uniqueOrdersInFile.size,
          totalQty: normalizedRows.reduce((sum, r) => sum + r.qty, 0),
          orderDate: bestDate,
          status: 'File preparing',
          assignee: '',
          uploadTimestamp: Date.now()
        });
      }
      setFiles(prev => [...prev, ...newProcessedFiles]);
    } catch (err: any) {
      setError("Error parsing Excel files.");
    } finally {
      setIsProcessing(false);
      e.target.value = ''; 
    }
  };

  const metrics = useMemo(() => {
    const allRows = files.flatMap(f => f.rows);
    const globalUniqueOrders = files.reduce((sum, f) => sum + f.totalOrders, 0);

    const getUniqueCountByCategories = (cats: ClubCategory[]) => {
      return files.filter(f => cats.includes(f.category)).reduce((sum, f) => sum + f.totalOrders, 0);
    };

    const duplicates: { id: string, club: string, material: string }[] = [];
    if (masterReconKeys.size > 0) {
      const rowsToCheck = allRows.length > 0 ? allRows : [];
      rowsToCheck.forEach(row => {
        const compositeKey = `${row.orderId}${row.material}`;
        if (masterReconKeys.has(compositeKey)) {
          duplicates.push({ id: row.orderId, club: row.clubName, material: row.material });
        }
      });
    }

    return {
      globalUniqueOrders,
      replacementTotal: getUniqueCountByCategories(['REPLACEMENT']),
      multipleTotal: getUniqueCountByCategories(['MULTIPLE_CLUBS']),
      multiSportTotal: getUniqueCountByCategories(['MULTI_SPORT']),
      rushAggregateTotal: getUniqueCountByCategories(['RUSH_RS', 'RUSH_RSA', 'RUSH_MIAMI']),
      duplicateCount: duplicates.length,
      duplicates
    };
  }, [files, masterReconKeys]);

  const handleStatusChange = (fileId: string, newStatus: ClubFileStatus) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, status: newStatus } : f));
  };

  const handleAssigneeChange = (fileId: string, assignee: string) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, assignee } : f));
  };

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Club Order Management</h1>
          <p className="text-slate-500 text-sm">Efficient processing with automated SAP reconciliation</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
           <div className="flex items-center gap-2 bg-white p-2 rounded-lg shadow-sm border border-slate-200">
              <div className="px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-500 uppercase">Batch #</div>
              {isBatchLocked ? (
                <div className="flex items-center gap-3 pl-2 pr-2">
                  <span className="text-lg font-bold text-slate-800 font-mono tracking-tight">{batchNumber}</span>
                  <button onClick={() => { setIsBatchLocked(false); setFiles([]); }} className="text-xs text-brand-600 font-bold hover:underline">CHANGE</button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <input type="text" value={batchNumber} onChange={(e) => setBatchNumber(e.target.value)} placeholder="e.g. 52#1" className="bg-white border border-slate-300 rounded px-3 py-1 text-slate-800 font-bold w-32 outline-none focus:ring-2 focus:ring-brand-500" />
                  <button disabled={!batchNumber || isProcessing} onClick={() => loadBatch(batchNumber)} className="bg-brand-600 text-white px-4 py-1 rounded text-sm font-bold hover:bg-brand-700 disabled:opacity-50 shadow-sm transition-all active:scale-95">SET</button>
                </div>
              )}
           </div>
           {isAdmin && isBatchLocked && files.length > 0 && (
             <button onClick={handleSaveBatch} disabled={isSaving} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-2 rounded-lg shadow-md transition-all active:scale-95 disabled:opacity-50 font-bold">
               {isSaving ? 'SYNCING...' : 'SYNC TO MASTER'}
             </button>
           )}
        </div>
      </div>

      {files.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 animate-fade-in-up">
           <KpiCard title="Batch Orders" value={metrics.globalUniqueOrders} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-indigo-600" />
           <KpiCard title="SAP Duplicates" value={metrics.duplicateCount} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>} colorClass="text-red-600" onClick={verifyDuplicatesAgainstMaster} subtext={verifyingDuplicates ? "Checking..." : "Click to verify"} />
           <KpiCard title="Rush Total" value={metrics.rushAggregateTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>} colorClass="text-amber-600" />
