        const compositeKey = `${row.orderId}${row.material}`;
        if (masterReconKeys.has(compositeKey)) {
          duplicates.push({ id: row.orderId, club: row.clubName, material: row.material });
        }
      });
    }
    return {
      globalUniqueOrders,
      replacementTotal: getUniqueCountByCategories(['REPLACEMENT']),
      multipleTotal: getUniqueCountByCategories(['MULTIPLE_CLUBS']),
      multiSportTotal: getUniqueCountByCategories(['MULTI_SPORT']),
