           <KpiCard title="SAP Duplicates" value={metrics.duplicateCount} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>} colorClass="text-red-600" onClick={verifyDuplicatesAgainstMaster} subtext={verifyingDuplicates ? "Checking..." : "Click to verify"} />
           <KpiCard title="Rush Total" value={metrics.rushAggregateTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>} colorClass="text-amber-600" />
           <KpiCard title="Replacement" value={metrics.replacementTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>} colorClass="text-emerald-600" />
           <KpiCard title="Multiple Club" value={metrics.multipleTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>} colorClass="text-purple-600" />
           <KpiCard title="Multi-sport" value={metrics.multiSportTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-teal-600" />
        </div>
      )}

      {showDuplicates && (
         <div className="bg-white border border-red-100 rounded-xl shadow-soft overflow-hidden animate-fade-in-down">
            <div className="px-6 py-4 bg-red-50 border-b border-red-100 flex justify-between items-center">
               <h3 className="text-lg font-bold text-red-800 flex items-center gap-2 uppercase tracking-wide">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                 SAP Reconciliation Matches
               </h3>
               <button onClick={() => setShowDuplicates(false)} className="text-red-500 hover:text-red-700 transition-colors"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="max-h-64 overflow-y-auto scrollbar-thin">
               <table className="min-w-full divide-y divide-red-100">
                 <thead className="bg-red-50/50 text-left sticky top-0 z-10">
                    <tr><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Order ID</th><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Club</th><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Material</th></tr>
                 </thead>
                 <tbody className="bg-white divide-y divide-red-50">
                    {metrics.duplicates.length > 0 ? metrics.duplicates.map((dup, i) => (
