               </table>
            </div>
         </div>
      )}

      <div className={`border-2 border-dashed rounded-2xl p-12 text-center transition-all duration-300 ${isBatchLocked ? 'border-brand-300 bg-brand-50/50 hover:bg-brand-50 cursor-pointer shadow-inner' : 'border-slate-200 bg-slate-50 opacity-60'}`}>
         <input type="file" multiple accept=".xlsx,.xls" onChange={handleFileUpload} disabled={!isBatchLocked || isProcessing} className="hidden" id="file-upload" />
         <label htmlFor="file-upload" className="flex flex-col items-center justify-center cursor-pointer">
           {isProcessing ? <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600 mb-4"></div> : 
             <><div className="p-5 rounded-full bg-white text-brand-600 shadow-soft mb-4 group-hover:scale-110 transition-transform"><svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg></div>
             <h3 className="text-xl font-bold text-slate-800 mb-1">{isBatchLocked ? 'Upload files for current batch' : 'Set a Batch Number to upload'}</h3>
             <p className="text-sm text-slate-500 font-medium">Drag and drop Excel files here</p></>}
         </label>
      </div>

      {files.length > 0 && (
        <div className="bg-white rounded-2xl shadow-card border border-slate-100 overflow-hidden animate-fade-in-up">
          <div className="px-8 py-6 border-b flex flex-col md:flex-row justify-between items-center bg-white gap-4">
             <div><h3 className="text-xl font-bold text-slate-800 tracking-tight">Files Summary</h3><p className="text-sm text-slate-500 font-medium">{files.length} club files active</p></div>
             <div className="relative w-full md:w-72">
                <input type="text" placeholder="Search clubs..." value={searchText} onChange={(e) => setSearchText(e.target.value)} className="w-full px-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 focus:bg-white shadow-sm transition-all" />
                <svg className="absolute left-3.5 top-3 w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-100">
              <thead className="bg-slate-50/80 text-left">
                <tr><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Club File Name</th><th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Orders</th><th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Qty</th><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Status</th><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Assigned</th><th className="px-8 py-4 text-right text-xs font-bold text-slate-500 uppercase tracking-widest">Action</th></tr>
              </thead>
              <tbody className="bg-white divide-y divide-slate-50">
                {files.filter(f => f.name.toLowerCase().includes(searchText.toLowerCase())).map(file => (
                  <tr key={file.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-8 py-5">
                      <div className="text-sm font-bold text-slate-900 truncate max-w-xs group-hover:text-brand-700 transition-colors" title={file.name}>{file.name}</div>
                      <div className="text-[10px] text-slate-400 font-bold uppercase tracking-tight mt-0.5">{file.category.replace('_', ' ')}</div>
                    </td>
                    <td className="px-6 py-5 text-center"><span className="px-3 py-1 bg-slate-100 rounded-lg text-sm font-bold text-slate-700">{file.totalOrders}</span></td>
                    <td className="px-6 py-5 text-center font-bold text-slate-600 text-sm">{file.totalQty.toLocaleString()}</td>
                    <td className="px-8 py-5">
                       <div className="flex flex-col gap-1.5 min-w-[120px]">
                         <select 
                           value={file.status} 
                           onChange={(e) => handleLocalUpdate(file.id, { status: e.target.value as ClubFileStatus })} 
                           className="text-[11px] font-bold text-slate-700 bg-white border border-slate-200 rounded-md py-1 px-1.5 outline-none focus:ring-1 focus:ring-brand-500 shadow-sm"
                         >
                           {CLUB_FILE_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                         </select>
                         <StatusBadge status={file.status} />
                       </div>
                    </td>
                    <td className="px-8 py-5">
                       <select 
                         value={file.assignee} 
                         onChange={(e) => handleLocalUpdate(file.id, { assignee: e.target.value })} 
                         className="text-[11px] font-semibold text-slate-800 bg-white border border-slate-200 rounded-md py-1 px-1.5 w-32 outline-none focus:ring-1 focus:ring-brand-500 shadow-sm"
                       >
                         <option value="">Unassigned</option>
                         {availableUsers.map(name => <option key={name} value={name}>{name}</option>)}
                       </select>
                    </td>
                    <td className="px-8 py-5 text-right"><button onClick={() => setEditFileId(file.id)} className="text-brand-600 bg-brand-50 px-4 py-2 rounded-xl hover:bg-brand-600 hover:text-white font-bold text-xs transition-all shadow-sm">EDIT</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* EDIT MODAL */}
      {editFileId && editingFile && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-scale-up">
              <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
                 <div><h3 className="font-bold text-slate-900 text-xl tracking-tight">Edit Summary Info</h3><p className="text-sm text-slate-500 font-medium truncate max-w-[300px]">{editingFile.name}</p></div>
                 <button onClick={() => setEditFileId(null)} className="text-slate-400 hover:text-slate-900 transition-colors p-2 bg-white rounded-full shadow-sm"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
              <div className="p-8 space-y-6">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">File Status</label>
                  <select 
                    value={editingFile.status} 
                    onChange={(e) => handleLocalUpdate(editingFile.id, { status: e.target.value as ClubFileStatus })} 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 transition-all"
                  >
                    {CLUB_FILE_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Assigned To</label>
                  <select 
                    value={editingFile.assignee} 
                    onChange={(e) => handleLocalUpdate(editingFile.id, { assignee: e.target.value })} 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 transition-all"
                  >
                    <option value="">Unassigned</option>
                    {availableUsers.map(name => <option key={name} value={name}>{name}</option>)}
                  </select>
                </div>

                <div className="pt-4 flex gap-3">
                  <button onClick={() => setEditFileId(null)} className="flex-1 px-6 py-3 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors">CANCEL</button>
                  <button onClick={() => handleUpdateSummaryRecord(editingFile)} disabled={isSaving} className="flex-1 px-6 py-3 bg-brand-600 text-white rounded-xl text-sm font-bold hover:bg-brand-700 shadow-lg shadow-brand-500/30 transition-all disabled:opacity-50">
                    {isSaving ? 'UPDATING...' : 'UPDATE'}
                  </button>
                </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { db } from '../services/firebase';
import { ref, query, orderByChild, limitToLast, get, endAt } from 'firebase/database';
import type { OrderRecord } from '../types';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const SEARCH_FIELDS = [
  { label: 'Order Number', key: 'OrderNumber' },
  { label: 'Material', key: 'Material Number' },
  { label: 'Sales Document', key: 'SalesDocument' },
  { label: 'Batch', key: 'BatchNumber' },
  { label: 'Status', key: 'Status' } 
];

const STATUS_FILTER_OPTIONS = [
  'Shipped',
  'Canceled',
  'Duplicate',
  'PA',
  'Not shipped'
];

interface ReconciliationProps {
  onEdit: (id: string) => void;
}

export const Reconciliation: React.FC<ReconciliationProps> = ({ onEdit }) => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  const [mode, setMode] = useState<'BROWSE' | 'SEARCH'>('BROWSE');
  const modeRef = useRef(mode);
  useEffect(() => {
    modeRef.current = mode;
  }, [mode]);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [browseOrders, setBrowseOrders] = useState<OrderRecord[]>([]);
  const [cursorStack, setCursorStack] = useState<Map<number, {value: any, key: string} | null>>(new Map());
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(true);

  const [allData, setAllData] = useState<OrderRecord[]>([]);
  const [searchField, setSearchField] = useState(SEARCH_FIELDS[0].key);
  const [searchText, setSearchText] = useState('');
  const [statusFilters, setStatusFilters] = useState<string[]>([]);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);

  // --- Logic Helpers ---

  const getCalculatedType = (order: OrderRecord): string => {
    // 1. Logic for MTO keyword in batch or record metadata
    const clubNameStr = String(order.ClubName || '').toUpperCase();
    const batchStr = String(order.BatchNumber || '').toUpperCase();

    if (clubNameStr.includes('MTO') || batchStr.includes('MTO')) {
      return 'MTO';
    }

    // 2. Logic for Sales Document prefix
    const salesDoc = String(order.SalesDocument || '');
    if (salesDoc.startsWith('1000')) return 'ZBC';
    if (salesDoc.startsWith('450')) return 'ZRP';
    if (salesDoc.startsWith('750')) return 'ZMO';
    if (salesDoc.startsWith('650')) return 'ZBO';

    return String(order.OrderType || 'N/A');
  };

  const getCalculatedCDD = (order: OrderRecord): string => {
    if (!order.OrderDate) return 'N/A';

    try {
      // Use original OrderDate as baseline
      const baseDate = new Date(String(order.OrderDate));
      if (isNaN(baseDate.getTime())) return String(order.CDD || 'N/A');

      // Logic: If club name contains "Replacements as", offset +2 days. Else +4 days.
      const clubNameLower = String(order.ClubName || '').toLowerCase();
      const isReplacement = clubNameLower.includes('replacements as');

      const offset = isReplacement ? 2 : 4;
      const cddDate = new Date(baseDate);
      cddDate.setDate(baseDate.getDate() + offset);

      // Format M/D/YY (e.g., 1/9/25)
      const m = cddDate.getMonth() + 1;
      const d = cddDate.getDate();
      const y = cddDate.getFullYear().toString().slice(-2);
      return `${m}/${d}/${y}`;
    } catch (e) {
      return String(order.CDD || 'N/A');
    }
  };

  // --- Data Fetching ---

  const fetchBrowsePage = async (page: number, cursor: {value: any, key: string} | null) => {
    if (modeRef.current === 'SEARCH') return;

    setLoading(true);
    setError(null);
    try {
      const dbRef = ref(db, 'order_management/master_recon_file');
      let q;
      const baseQuery = query(dbRef, orderByChild('OrderDate'));

      if (cursor) {
        q = query(baseQuery, endAt(cursor.value, cursor.key), limitToLast(PAGE_SIZE + 1));
      } else {
        q = query(baseQuery, limitToLast(PAGE_SIZE));
      }

      const snapshot = await get(q);
      if ((modeRef.current as string) === 'SEARCH') {
          setLoading(false);
          return;
      }

      if (snapshot.exists()) {
        const raw: OrderRecord[] = [];
        snapshot.forEach(c => {
          raw.push({ ...c.val(), Code: c.key as string });
        });

        if (cursor) {
           const last = raw[raw.length - 1];
           if (last && last.Code === cursor.key) raw.pop();
        }

        if (raw.length > 0) {
            const boundary = raw[0];
            setCursorStack(prev => {
                const map = new Map(prev);
                map.set(page + 1, { value: boundary.OrderDate, key: boundary.Code });
                return map;
            });
            setHasNextPage(true);
        } else {
            setHasNextPage(false);
        }

        setBrowseOrders(raw.reverse());
      } else {
        setBrowseOrders([]);
        setHasNextPage(false);
      }
    } catch (err: any) {
      console.error(err);
      if (modeRef.current === 'BROWSE') setError(err.message || 'Failed to load data');
    } finally {
      if (modeRef.current === 'BROWSE') setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === 'BROWSE') {
        const cursor = currentPage === 1 ? null : cursorStack.get(currentPage) || null;
        fetchBrowsePage(currentPage, cursor);
    }
  }, [mode, currentPage]);

  const initSearch = async () => {
    setMode('SEARCH');
    setLoading(true);
    setError(null);
    try {
        const dbRef = ref(db, 'order_management/master_recon_file');
        const snapshot = await get(dbRef); 
        if (snapshot.exists()) {
            const val = snapshot.val();
            const fullList: OrderRecord[] = [];
            Object.entries(val).forEach(([key, value]: [string, any]) => {
                fullList.push({ ...value, Code: key });
            });
            fullList.sort((a, b) => {
                const da = a.OrderDate ? new Date(String(a.OrderDate)).getTime() : 0;
                const db = b.OrderDate ? new Date(String(b.OrderDate)).getTime() : 0;
                return db - da;
            });
            setAllData(fullList);
            setCurrentPage(1);
        } else {
            setAllData([]);
        }
    } catch (err: any) {
        setError("Failed to download database.");
    } finally {
        setLoading(false);
    }
  };

  const searchResults = useMemo(() => {
    if (mode !== 'SEARCH') return [];
    return allData.filter(order => {
        if (searchText.trim()) {
            const val = order[searchField];
            if (!val || !String(val).toLowerCase().includes(searchText.toLowerCase())) return false;
        }
        if (statusFilters.length > 0) {
            const s = (order.Status || '').toLowerCase();
            if (!statusFilters.some(filter => s.includes(filter.toLowerCase()))) return false;
        }
        return true;
    });
  }, [allData, mode, searchText, searchField, statusFilters]);

  const currentSearchPageData = useMemo(() => {
     const start = (currentPage - 1) * PAGE_SIZE;
     return searchResults.slice(start, start + PAGE_SIZE);
  }, [searchResults, currentPage]);

  const handleSearchSubmit = (e: React.FormEvent) => { e.preventDefault(); if (mode === 'BROWSE') initSearch(); };
  const handleClear = () => { setSearchText(''); setStatusFilters([]); setMode('BROWSE'); setCurrentPage(1); setCursorStack(new Map()); setAllData([]); };
  const toggleFilter = (option: string) => {
      const newFilters = statusFilters.includes(option) ? statusFilters.filter(f => f !== option) : [...statusFilters, option];
      setStatusFilters(newFilters);
      if (mode === 'BROWSE' && newFilters.length > 0) initSearch();
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => { if (filterRef.current && !filterRef.current.contains(event.target as Node)) setIsFilterOpen(false); };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const activeData = mode === 'BROWSE' ? browseOrders : currentSearchPageData;

  return (
    <div className="flex flex-col gap-6 h-full">
      <div className="bg-white rounded-xl shadow-soft border border-slate-100 p-4 z-20">
        <form onSubmit={handleSearchSubmit} className="flex flex-col xl:flex-row gap-4 xl:items-center justify-between">
            <div className="flex flex-col md:flex-row gap-2 w-full xl:w-auto flex-1">
                <div className="w-full md:w-40 xl:w-48">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Search By</label>
