                </div>
              ) : (
                <div className="flex gap-2">
                  <input type="text" value={batchNumber} onChange={(e) => setBatchNumber(e.target.value)} placeholder="e.g. 52#1" className="bg-white border border-slate-300 rounded px-3 py-1 text-slate-800 font-bold w-32 outline-none focus:ring-2 focus:ring-brand-500" />
                  <button disabled={!batchNumber || isProcessing} onClick={() => loadBatch(batchNumber)} className="bg-brand-600 text-white px-4 py-1 rounded text-sm font-bold hover:bg-brand-700 shadow-sm transition-all active:scale-95">SET</button>
                </div>
