             <div><h3 className="text-xl font-bold text-slate-800 tracking-tight">Files Summary</h3><p className="text-sm text-slate-500 font-medium">{files.length} club files active</p></div>
             <div className="relative w-full md:w-72">
                <input type="text" placeholder="Search clubs..." value={searchText} onChange={(e) => setSearchText(e.target.value)} className="w-full px-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 focus:bg-white shadow-sm transition-all" />
                <svg className="absolute left-3.5 top-3 w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
