                    <td className="px-8 py-5 text-sm font-black text-brand-700 font-mono">{file.cdd || 'N/A'}</td>
                    <td className="px-8 py-5">
                       <div className="flex flex-col gap-1.5 min-w-[120px]">
                         <select 
