                           onChange={(e) => handleLocalUpdate(file.id, { status: e.target.value as ClubFileStatus })} 
                           className="text-[11px] font-bold text-slate-700 bg-white border border-slate-200 rounded-md py-1 px-1.5 outline-none focus:ring-1 focus:ring-brand-500 shadow-sm"
                         >
                           {CLUB_FILE_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
