import React, { useState, useMemo, useEffect } from 'react';
import { db } from '../services/firebase';
import { ref, get, update, push } from 'firebase/database';
import { CLUB_FILE_STATUSES, ClubFileStatus, ClubCategory, ProcessedFile, ClubOrderRow } from '../types';
import { useAuth } from '../context/AuthContext';

declare const XLSX: any;

const generateId = () => Math.random().toString(36).substr(2, 9);

const sanitizeKey = (key: string) => key.replace(/#/g, '_HASH_');
const desanitizeKey = (key: string) => key.replace(/_HASH_/g, '#');

interface ProcessedFileWithCDD extends ProcessedFile {
  cdd: string;
}

const detectCategory = (filename: string): ClubCategory => {
  const lower = filename.toLowerCase();
  const multiSportKeywords = ['baseball', 'hockey', 'volleyball', 'basketball', 'lacrosse', 'mto', 'multi-sport', 'multisport'];
  if (multiSportKeywords.some(keyword => lower.includes(keyword))) return 'MULTI_SPORT';
  if (lower.includes('multiple clubs')) return 'MULTIPLE_CLUBS';
  if (lower.includes('rush rs') && !lower.includes('rsa')) return 'RUSH_RS';
  if (lower.includes('rush rsa')) return 'RUSH_RSA';
  if (lower.includes('rush miami')) return 'RUSH_MIAMI';
  if (lower.includes('replacement') || lower.includes('replacements')) return 'REPLACEMENT';
  return 'OTHER';
};

const calculateCDDForFile = (orderDate: string, filename: string): string => {
  if (!orderDate) return '';
  try {
    const baseDate = new Date(orderDate);
    if (isNaN(baseDate.getTime())) return '';
    const isReplacement = filename.toLowerCase().includes('replacements as');
    const offset = isReplacement ? 2 : 4;
    const cddDate = new Date(baseDate);
    cddDate.setDate(baseDate.getDate() + offset);
    const mm = String(cddDate.getMonth() + 1).padStart(2, '0');
    const dd = String(cddDate.getDate()).padStart(2, '0');
    const yyyy = cddDate.getFullYear();
    return `${mm}/${dd}/${yyyy}`;
  } catch (e) {
    return '';
  }
};

const normalizeHeader = (header: string): string => {
  return header.toString().trim().toLowerCase().replace(/[\s#]/g, '');
};

const parseExcelDate = (value: any): string => {
  if (!value) return '';
  if (typeof value === 'number') {
    const date = new Date(Math.round((value - 25569) * 86400 * 1000));
    return date.toISOString().split('T')[0];
  }
  const d = new Date(value);
  if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];
  return String(value);
};

const resolveLatestBatch = (keys: string[]): string | null => {
  if (keys.length === 0) return null;
  return [...keys].sort((a, b) => {
    const aParts = a.replace(/_HASH_/g, '#').split('#').map(n => parseInt(n) || 0);
    const bParts = b.replace(/_HASH_/g, '#').split('#').map(n => parseInt(n) || 0);
    if (aParts[0] !== bParts[0]) return bParts[0] - aParts[0];
    return (bParts[1] || 0) - (aParts[1] || 0);
  })[0];
};

const StatusBadge: React.FC<{ status: ClubFileStatus }> = ({ status }) => {
  const colors: Record<ClubFileStatus, string> = {
    'File preparing': 'bg-slate-100 text-slate-700 border-slate-200',
    'Packing list checking': 'bg-blue-100 text-blue-700 border-blue-200',
    'Correction': 'bg-orange-100 text-orange-700 border-orange-200',
    'Share': 'bg-emerald-100 text-emerald-700 border-emerald-200',
  };
  return (
    <span className={`px-2 py-0.5 text-[9px] font-bold rounded-full border uppercase tracking-wider ${colors[status]}`}>
      {status}
    </span>
  );
};

const KpiCard: React.FC<{ title: string; value: number | string; icon: React.ReactNode; colorClass: string; subtext?: string; onClick?: () => void }> = ({ 
  title, value, icon, colorClass, subtext, onClick 
}) => (
  <div onClick={onClick} className={`bg-white rounded-xl p-5 border border-slate-100 shadow-soft relative overflow-hidden group hover:shadow-card transition-all ${onClick ? 'cursor-pointer' : ''}`}>
    <div className={`absolute top-0 right-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity ${colorClass}`}>
      {React.cloneElement(icon as React.ReactElement<any>, { className: "w-16 h-16" })}
    </div>
    <div className="relative z-10">
      <div className={`h-10 w-10 rounded-lg flex items-center justify-center mb-3 ${colorClass} bg-opacity-10 text-current`}>
        {icon}
      </div>
      <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
      <div className="flex items-baseline gap-2">
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
        {subtext && <span className="text-xs text-slate-400 font-medium">{subtext}</span>}
      </div>
    </div>
  </div>
);

export const ClubOrder: React.FC = () => {
  const { userProfile } = useAuth();
  const isAdmin = userProfile?.role === 'admin';

  const [batchNumber, setBatchNumber] = useState('');
  const [isBatchLocked, setIsBatchLocked] = useState(false);
  const [allBatchKeys, setAllBatchKeys] = useState<string[]>([]);
  const [files, setFiles] = useState<ProcessedFileWithCDD[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [showDuplicates, setShowDuplicates] = useState(false);
  const [editFileId, setEditFileId] = useState<string | null>(null);
  const [searchText, setSearchText] = useState('');
  const [masterReconKeys, setMasterReconKeys] = useState<Set<string>>(new Set());
  const [verifyingDuplicates, setVerifyingDuplicates] = useState(false);
  const [availableUsers, setAvailableUsers] = useState<string[]>([]);

  // Persistent unique ID for the user's session/daily group node
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      try {
        const collectionRef = ref(db, 'order_management/club_collection');
        const snapshot = await get(collectionRef);
        if (snapshot.exists()) {
          const val = snapshot.val();
          const foundBatches: string[] = [];

          // Traverse nested structure: club_collection -> UniqueID -> Batch#
          Object.keys(val).forEach(uniqueId => {
            const batches = val[uniqueId];
            if (typeof batches === 'object') {
              Object.keys(batches).forEach(bKey => {
                foundBatches.push(desanitizeKey(bKey));
              });
            }
          });

          setAllBatchKeys([...new Set(foundBatches)]);
          const latestDisplay = resolveLatestBatch(foundBatches);
          if (latestDisplay) {
            setBatchNumber(latestDisplay);
            loadBatch(latestDisplay);
          }
        }

        const usersRef = ref(db, 'users');
        const usersSnapshot = await get(usersRef);
        if (usersSnapshot.exists()) {
          const usersData = usersSnapshot.val();
          const names = Object.values(usersData).map((u: any) => u.name).filter(Boolean);
          setAvailableUsers(names);
        }
      } catch (err) {
        console.error("Init load error:", err);
      }
    };
    init();
  }, []);

  const loadBatch = async (displayKey: string) => {
    if (!displayKey) return;
    setIsProcessing(true);
    setError(null);
    const safeKey = sanitizeKey(displayKey);
    try {
      const collectionRef = ref(db, 'order_management/club_collection');
      const snapshot = await get(collectionRef);
      if (snapshot.exists()) {
        const val = snapshot.val();
        let batchData: any = null;
        let sessionId: string | null = null;

        // Find which unique ID contains this batch
        for (const uId in val) {
          if (val[uId][safeKey]) {
            batchData = val[uId][safeKey];
            sessionId = uId;
            break;
          }
        }

        if (batchData) {
          setCurrentSessionId(sessionId);
          const loadedFiles: ProcessedFileWithCDD[] = Object.entries(batchData).map(([fileName, details]: [string, any]) => {
            if (['date', 'global_orders', 'uploaded_by', 'metadata'].includes(fileName)) return null;
            const name = fileName.replace(/_DOT_/g, '.');
            return {
              id: generateId(),
              name: name,
              totalOrders: details.order || 0,
              totalQty: details.qty || 0,
              status: details.status || 'File preparing',
              assignee: details.assigned || '',
              cdd: details.CDD || '',
              category: detectCategory(name),
              rows: [], 
              uploadTimestamp: Date.now(),
              orderDate: ''
            };
          }).filter(f => f !== null) as ProcessedFileWithCDD[];
          setFiles(loadedFiles);
        } else {
          setFiles([]);
          setCurrentSessionId(null);
        }
      }
      setIsBatchLocked(true);
    } catch (err: any) {
      setError("Failed to connect to database.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleUpdateSummaryRecord = async (file: ProcessedFileWithCDD) => {
    if (!isAdmin || !batchNumber || !currentSessionId) return;
    setIsSaving(true);
    const safeBatchKey = sanitizeKey(batchNumber);
    const safeFileName = file.name.replace(/\./g, '_DOT_');

    try {
      const updateData = {
        [`order_management/club_collection/${currentSessionId}/${safeBatchKey}/${safeFileName}/status`]: file.status,
        [`order_management/club_collection/${currentSessionId}/${safeBatchKey}/${safeFileName}/assigned`]: file.assignee,
        [`order_management/club_collection/${currentSessionId}/${safeBatchKey}/${safeFileName}/CDD`]: file.cdd,
      };
      await update(ref(db), updateData);
      setEditFileId(null);
    } catch (err) {
      console.error(err);
      alert("Failed to update record in Firebase.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleSaveBatch = async () => {
    if (!isAdmin || !batchNumber || files.length === 0) return;
    setIsSaving(true);
    const safeBatchKey = sanitizeKey(batchNumber);
    const updates: Record<string, any> = {};

    try {
      // Use current user UID or existing session ID
      let sessionId = currentSessionId;
      if (!sessionId) {
        sessionId = userProfile?.uid || generateId();
        setCurrentSessionId(sessionId);
      }

      const allRows = files.flatMap(f => f.rows);
      const globalUniqueOrders = new Set(allRows.map(r => r.orderId)).size;

      // System date formatting MM/DD/YYYY
      const now = new Date();
      const sysDate = `${now.getMonth() + 1}/${now.getDate()}/${now.getFullYear()}`;

      const batchSummary: Record<string, any> = {
        date: sysDate,
        global_orders: globalUniqueOrders || files.reduce((s,f) => s+f.totalOrders,0),
        uploaded_by: userProfile?.name || 'Master Admin'
      };

      files.forEach(f => {
        const safeFileName = f.name.replace(/\./g, '_DOT_');
        batchSummary[safeFileName] = {
          order: f.totalOrders,
          qty: f.totalQty,
          status: f.status,
          assigned: f.assignee,
          CDD: f.cdd
        };
      });

      // Store under unique session ID and then Batch Key
      updates[`order_management/club_collection/${sessionId}/${safeBatchKey}`] = batchSummary;

      allRows.forEach(row => {
        const detailKey = `${row.orderId}${row.material}`;
        updates[`order_management/master_recon_file/${detailKey}`] = {
          OrderNumber: row.orderId,
          SalesDocument: row.salesDoc,
          OrderDate: row.orderDate,
          BatchNumber: batchNumber,
          Year: new Date(row.orderDate).getFullYear() || "2025",
          "Material Number": row.material,
          ClubName: row.clubName,
          OrderType: null,
          Status: "file preparing",
          CDD: null,
          qty: row.qty,
          sku: row.sku,
          productName: row.productName
        };
      });

      await update(ref(db), updates);
      if (!allBatchKeys.includes(batchNumber)) {
        setAllBatchKeys(prev => [...prev, batchNumber]);
      }
      alert(`Batch ${batchNumber} saved successfully under ID ${sessionId}.`);
    } catch (err) {
      console.error(err);
      setError("Failed to save data.");
    } finally {
      setIsSaving(false);
    }
  };

  const verifyDuplicatesAgainstMaster = async () => {
    if (files.length === 0) return;
    setVerifyingDuplicates(true);
    try {
      const reconRef = ref(db, 'order_management/master_recon_file');
      const snapshot = await get(reconRef);
      if (snapshot.exists()) {
        const reconData = snapshot.val();
        const keys = new Set(Object.keys(reconData));
        setMasterReconKeys(keys);
        setShowDuplicates(true);
      }
    } catch (err) {
      setError("Failed to verify duplicates.");
    } finally {
      setVerifyingDuplicates(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;
    setIsProcessing(true);
    setError(null);
    const uploadedFiles = Array.from(e.target.files);
    const newProcessedFiles: ProcessedFileWithCDD[] = [];

    try {
      for (const file of uploadedFiles) {
        if (file.name.toLowerCase().includes('combine')) continue;
        const data = await file.arrayBuffer();
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet);

        const normalizedRows: ClubOrderRow[] = [];
        rawJson.forEach((row: any) => {
          let orderId = '', salesDoc = '', orderDate = '', qty = 0, sku = '', material = '', productName = '', clubName = '';
          Object.keys(row).forEach(key => {
            const normKey = normalizeHeader(key);
            const val = row[key];
            if (normKey.includes('orderid') || normKey === 'order') orderId = String(val).trim();
            else if (normKey.includes('salesdoc')) salesDoc = String(val).trim();
            else if (normKey.includes('orderdate') || normKey === 'date') orderDate = parseExcelDate(val);
            else if (normKey.includes('qty') || normKey.includes('quantity')) qty = Number(val) || 0;
            else if (normKey.includes('sku')) sku = String(val);
            else if (normKey.includes('material')) material = String(val);
            else if (normKey.includes('productname') || normKey.includes('description')) productName = String(val);
            else if (normKey.includes('clubname') || normKey.includes('club')) clubName = String(val);
          });
          if (orderId) normalizedRows.push({ orderId, salesDoc, orderDate, qty, sku, material, productName, clubName, raw: row });
        });

        if (normalizedRows.length === 0) continue;

        const uniqueOrdersInFile = new Set(normalizedRows.map(r => r.orderId));
        const dateCounts: Record<string, number> = {};
        normalizedRows.forEach(r => { if(r.orderDate) dateCounts[r.orderDate] = (dateCounts[r.orderDate] || 0) + 1; });
        const bestDate = Object.keys(dateCounts).sort((a,b) => dateCounts[b] - dateCounts[a])[0] || '';

        newProcessedFiles.push({
          id: generateId(),
          name: file.name,
          category: detectCategory(file.name),
          rows: normalizedRows,
          totalOrders: uniqueOrdersInFile.size,
          totalQty: normalizedRows.reduce((sum, r) => sum + r.qty, 0),
          orderDate: bestDate,
          status: 'File preparing',
          assignee: '',
          cdd: calculateCDDForFile(bestDate, file.name),
          uploadTimestamp: Date.now()
        });
      }
      setFiles(prev => [...prev, ...newProcessedFiles]);
    } catch (err: any) {
      setError("Error parsing Excel files.");
    } finally {
      setIsProcessing(false);
      e.target.value = ''; 
    }
  };

  const metrics = useMemo(() => {
    const allRows = files.flatMap(f => f.rows);
    const globalUniqueOrders = files.reduce((sum, f) => sum + f.totalOrders, 0);
    const getUniqueCountByCategories = (cats: ClubCategory[]) => {
      return files.filter(f => cats.includes(f.category)).reduce((sum, f) => sum + f.totalOrders, 0);
    };
    const duplicates: { id: string, club: string, material: string }[] = [];
    if (masterReconKeys.size > 0) {
      const rowsToCheck = allRows.length > 0 ? allRows : [];
      rowsToCheck.forEach(row => {
        const compositeKey = `${row.orderId}${row.material}`;
        if (masterReconKeys.has(compositeKey)) {
          duplicates.push({ id: row.orderId, club: row.clubName, material: row.material });
        }
      });
    }
    return {
      globalUniqueOrders,
      replacementTotal: getUniqueCountByCategories(['REPLACEMENT']),
      multipleTotal: getUniqueCountByCategories(['MULTIPLE_CLUBS']),
      multiSportTotal: getUniqueCountByCategories(['MULTI_SPORT']),
      rushAggregateTotal: getUniqueCountByCategories(['RUSH_RS', 'RUSH_RSA', 'RUSH_MIAMI']),
      duplicateCount: duplicates.length,
      duplicates
    };
  }, [files, masterReconKeys]);

  const handleLocalUpdate = (fileId: string, updates: Partial<ProcessedFileWithCDD>) => {
    setFiles(prev => prev.map(f => f.id === fileId ? { ...f, ...updates } : f));
  };

  const editingFile = useMemo(() => files.find(f => f.id === editFileId), [files, editFileId]);

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Club Order Management</h1>
          <p className="text-slate-500 text-sm">Automated SAP reconciliation and summary tracking</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
           <div className="flex items-center gap-2 bg-white p-2 rounded-lg shadow-sm border border-slate-200">
              <div className="px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-500 uppercase">Batch #</div>
              {isBatchLocked ? (
                <div className="flex items-center gap-3 pl-2 pr-2">
                  <span className="text-lg font-bold text-slate-800 font-mono tracking-tight">{batchNumber}</span>
                  <button onClick={() => { setIsBatchLocked(false); setFiles([]); setCurrentSessionId(null); }} className="text-xs text-brand-600 font-bold hover:underline">CHANGE</button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <input type="text" value={batchNumber} onChange={(e) => setBatchNumber(e.target.value)} placeholder="e.g. 52#1" className="bg-white border border-slate-300 rounded px-3 py-1 text-slate-800 font-bold w-32 outline-none focus:ring-2 focus:ring-brand-500" />
                  <button disabled={!batchNumber || isProcessing} onClick={() => loadBatch(batchNumber)} className="bg-brand-600 text-white px-4 py-1 rounded text-sm font-bold hover:bg-brand-700 shadow-sm transition-all active:scale-95">SET</button>
                </div>
              )}
           </div>
           {isAdmin && isBatchLocked && files.length > 0 && (
             <button onClick={handleSaveBatch} disabled={isSaving} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-2 rounded-lg shadow-md transition-all active:scale-95 disabled:opacity-50 font-bold">
               {isSaving ? 'SYNCING...' : 'SYNC TO MASTER'}
             </button>
           )}
        </div>
      </div>

      {files.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 animate-fade-in-up">
           <KpiCard title="Batch Orders" value={metrics.globalUniqueOrders} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-indigo-600" />
           <KpiCard title="Duplicates Order" value={metrics.duplicateCount} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>} colorClass="text-red-600" onClick={verifyDuplicatesAgainstMaster} subtext={verifyingDuplicates ? "Checking..." : "Click to verify"} />
           <KpiCard title="Rush Total" value={metrics.rushAggregateTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>} colorClass="text-amber-600" />
           <KpiCard title="Replacement" value={metrics.replacementTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>} colorClass="text-emerald-600" />
           <KpiCard title="Multiple Club" value={metrics.multipleTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>} colorClass="text-purple-600" />
           <KpiCard title="Multi-sport" value={metrics.multiSportTotal} icon={<svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} colorClass="text-teal-600" />
        </div>
      )}

      {showDuplicates && (
         <div className="bg-white border border-red-100 rounded-xl shadow-soft overflow-hidden animate-fade-in-down">
            <div className="px-6 py-4 bg-red-50 border-b border-red-100 flex justify-between items-center">
               <h3 className="text-lg font-bold text-red-800 flex items-center gap-2 uppercase tracking-wide">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                 SAP Reconciliation Matches
               </h3>
               <button onClick={() => setShowDuplicates(false)} className="text-red-500 hover:text-red-700 transition-colors"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="max-h-64 overflow-y-auto scrollbar-thin">
               <table className="min-w-full divide-y divide-red-100">
                 <thead className="bg-red-50/50 text-left sticky top-0 z-10">
                    <tr><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Order ID</th><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Club</th><th className="px-6 py-3 text-xs font-bold text-red-800 uppercase tracking-widest">Material</th></tr>
                 </thead>
                 <tbody className="bg-white divide-y divide-red-50">
                    {metrics.duplicates.length > 0 ? metrics.duplicates.map((dup, i) => (
                      <tr key={i} className="hover:bg-red-50/30 transition-colors"><td className="px-6 py-3 text-sm font-bold text-slate-900">{dup.id}</td><td className="px-6 py-3 text-sm text-slate-600">{dup.club}</td><td className="px-6 py-3 text-[10px] text-red-600 font-black uppercase tracking-tight">{dup.material}</td></tr>
                    )) : <tr><td colSpan={3} className="px-6 py-12 text-center text-slate-400 font-medium italic">No existing records found.</td></tr>}
                 </tbody>
               </table>
            </div>
         </div>
      )}

      <div className={`border-2 border-dashed rounded-2xl p-12 text-center transition-all duration-300 ${isBatchLocked ? 'border-brand-300 bg-brand-50/50 hover:bg-brand-50 cursor-pointer shadow-inner' : 'border-slate-200 bg-slate-50 opacity-60'}`}>
         <input type="file" multiple accept=".xlsx,.xls" onChange={handleFileUpload} disabled={!isBatchLocked || isProcessing} className="hidden" id="file-upload" />
         <label htmlFor="file-upload" className="flex flex-col items-center justify-center cursor-pointer">
           {isProcessing ? <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600 mb-4"></div> : 
             <><div className="p-5 rounded-full bg-white text-brand-600 shadow-soft mb-4 group-hover:scale-110 transition-transform"><svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg></div>
             <h3 className="text-xl font-bold text-slate-800 mb-1">{isBatchLocked ? 'Upload files for current batch' : 'Set a Batch Number to upload'}</h3>
             <p className="text-sm text-slate-500 font-medium">Drag and drop Excel files here</p></>}
         </label>
      </div>

      {files.length > 0 && (
        <div className="bg-white rounded-2xl shadow-card border border-slate-100 overflow-hidden animate-fade-in-up">
          <div className="px-8 py-6 border-b flex flex-col md:flex-row justify-between items-center bg-white gap-4">
             <div><h3 className="text-xl font-bold text-slate-800 tracking-tight">Files Summary</h3><p className="text-sm text-slate-500 font-medium">{files.length} club files active</p></div>
             <div className="relative w-full md:w-72">
                <input type="text" placeholder="Search clubs..." value={searchText} onChange={(e) => setSearchText(e.target.value)} className="w-full px-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 focus:bg-white shadow-sm transition-all" />
                <svg className="absolute left-3.5 top-3 w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-100">
              <thead className="bg-slate-50/80 text-left">
                <tr><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Club File Name</th><th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Orders</th><th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Qty</th><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">CDD</th><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Status</th><th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Assigned</th><th className="px-8 py-4 text-right text-xs font-bold text-slate-500 uppercase tracking-widest">Action</th></tr>
              </thead>
              <tbody className="bg-white divide-y divide-slate-50">
                {files.filter(f => f.name.toLowerCase().includes(searchText.toLowerCase())).map(file => (
                  <tr key={file.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-8 py-5">
                      <div className="text-sm font-bold text-slate-900 truncate max-w-xs group-hover:text-brand-700 transition-colors" title={file.name}>{file.name}</div>
                      <div className="text-[10px] text-slate-400 font-bold uppercase tracking-tight mt-0.5">{file.category.replace('_', ' ')}</div>
                    </td>
                    <td className="px-6 py-5 text-center"><span className="px-3 py-1 bg-slate-100 rounded-lg text-sm font-bold text-slate-700">{file.totalOrders}</span></td>
                    <td className="px-6 py-5 text-center font-bold text-slate-600 text-sm">{file.totalQty.toLocaleString()}</td>
                    <td className="px-8 py-5 text-sm font-black text-brand-700 font-mono">{file.cdd || 'N/A'}</td>
                    <td className="px-8 py-5">
                       <div className="flex flex-col gap-1.5 min-w-[120px]">
                         <select 
                           value={file.status} 
                           onChange={(e) => handleLocalUpdate(file.id, { status: e.target.value as ClubFileStatus })} 
                           className="text-[11px] font-bold text-slate-700 bg-white border border-slate-200 rounded-md py-1 px-1.5 outline-none focus:ring-1 focus:ring-brand-500 shadow-sm"
                         >
                           {CLUB_FILE_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                         </select>
                         <StatusBadge status={file.status} />
                       </div>
                    </td>
                    <td className="px-8 py-5">
                       <select 
                         value={file.assignee} 
                         onChange={(e) => handleLocalUpdate(file.id, { assignee: e.target.value })} 
                         className="text-[11px] font-semibold text-slate-800 bg-white border border-slate-200 rounded-md py-1 px-1.5 w-32 outline-none focus:ring-1 focus:ring-brand-500 shadow-sm"
                       >
                         <option value="">Unassigned</option>
                         {availableUsers.map(name => <option key={name} value={name}>{name}</option>)}
                       </select>
                    </td>
                    <td className="px-8 py-5 text-right"><button onClick={() => setEditFileId(file.id)} className="text-brand-600 bg-brand-50 px-4 py-2 rounded-xl hover:bg-brand-600 hover:text-white font-bold text-xs transition-all shadow-sm">EDIT</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* EDIT MODAL */}
      {editFileId && editingFile && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-scale-up">
              <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
                 <div><h3 className="font-bold text-slate-900 text-xl tracking-tight">Edit Summary Info</h3><p className="text-sm text-slate-500 font-medium truncate max-w-[300px]">{editingFile.name}</p></div>
                 <button onClick={() => setEditFileId(null)} className="text-slate-400 hover:text-slate-900 transition-colors p-2 bg-white rounded-full shadow-sm"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
              <div className="p-8 space-y-6">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">CDD Date</label>
                  <input 
                    type="text" 
                    value={editingFile.cdd}
                    onChange={(e) => handleLocalUpdate(editingFile.id, { cdd: e.target.value })}
                    placeholder="MM/DD/YYYY"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 transition-all"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">File Status</label>
                  <select 
                    value={editingFile.status} 
                    onChange={(e) => handleLocalUpdate(editingFile.id, { status: e.target.value as ClubFileStatus })} 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 transition-all"
                  >
                    {CLUB_FILE_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Assigned To</label>
                  <select 
                    value={editingFile.assignee} 
                    onChange={(e) => handleLocalUpdate(editingFile.id, { assignee: e.target.value })} 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-brand-500 transition-all"
                  >
                    <option value="">Unassigned</option>
                    {availableUsers.map(name => <option key={name} value={name}>{name}</option>)}
                  </select>
                </div>

                <div className="pt-4 flex gap-3">
                  <button onClick={() => setEditFileId(null)} className="flex-1 px-6 py-3 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors">CANCEL</button>
                  <button onClick={() => handleUpdateSummaryRecord(editingFile)} disabled={isSaving} className="flex-1 px-6 py-3 bg-brand-600 text-white rounded-xl text-sm font-bold hover:bg-brand-700 shadow-lg shadow-brand-500/30 transition-all disabled:opacity-50">
                    {isSaving ? 'UPDATING...' : 'UPDATE'}
                  </button>
                </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};
